function bootstrapLoginMode(bootstrap,server){const mode=String((bootstrap||{}).initialSshMode||"").trim().toLowerCase();if(SSH_MODE_CHOICES.some(function(i){return i.id===mode;}))return mode;const bootstrapReady=String((bootstrap||{}).status||"").trim().toLowerCase()==="ready";return bootstrapReady?"":resolveSshMode(server||{});}
function bootstrapLoginLabel(bootstrap,server){const mode=bootstrapLoginMode(bootstrap,server);return mode?sshModeLabel(mode):"Not recorded";}
function runtimeCollectionLabel(record,bootstrap){const server=(record||{}).server||{};const bootstrapReady=String((bootstrap||{}).status||"").trim().toLowerCase()==="ready";if(!bootstrapReady)return"Pending bootstrap";if(String((server.username||"root")).trim().toLowerCase()==="root")return"Installed runtime key";return server.sudoRequired?"Installed runtime key with sudo":"Installed runtime key";}
function normalizeIsoTimestamp(v){const text=String(v||"").trim();if(!text)return"";if(/z$/i.test(text)||/[+-]\d{2}:\d{2}$/.test(text))return text;const compactOffset=text.match(/([+-]\d{2})(\d{2})$/);if(compactOffset)return`${text.slice(0,-5)}${compactOffset[1]}:${compactOffset[2]}`;return text;}
function parseTimestamp(v,epochValue){if(epochValue!=null&&epochValue!==""){const epochNumber=Number(epochValue);if(Number.isFinite(epochNumber)&&epochNumber>0)return new Date(epochNumber*1000);}const normalized=normalizeIsoTimestamp(v);if(!normalized)return null;const parsed=new Date(normalized);return Number.isNaN(parsed.getTime())?null:parsed;}
function formatLocalTimestamp(v,epochValue,fallback){const parsed=parseTimestamp(v,epochValue);if(!parsed)return fallback||"-";return new Intl.DateTimeFormat(undefined,{weekday:"long",year:"numeric",month:"long",day:"2-digit",hour:"2-digit",minute:"2-digit",second:"2-digit",timeZoneName:"short"}).format(parsed);}
function formatHeaderTimestamp(v,epochValue,prefix,emptyCopy){const formatted=formatLocalTimestamp(v,epochValue,"");return formatted?`${prefix} ${formatted}`:(emptyCopy||"Not yet collected");}
function formatCollectorLogTimestamp(date){const value=date instanceof Date?date:new Date(date||Date.now());const year=value.getUTCFullYear();const month=String(value.getUTCMonth()+1).padStart(2,"0");const day=String(value.getUTCDate()).padStart(2,"0");let hours=value.getUTCHours();const minutes=String(value.getUTCMinutes()).padStart(2,"0");const seconds=String(value.getUTCSeconds()).padStart(2,"0");const ampm=hours>=12?"PM":"AM";hours=hours%12||12;return`${year}-${month}-${day} ${String(hours).padStart(2,"0")}:${minutes}:${seconds} ${ampm} UTC`;}
function collectorLogEnvironmentLabel(environmentName,environmentId){const safeName=String(environmentName||"").trim();const safeId=String(environmentId||"").trim();if(safeName&&safeId)return`${safeName} (${safeId})`;return safeName||safeId||"Environment";}
function trimCollectorTail(text,maxLines){const lines=String(text||"").split(/\r?\n/).map(function(line){return String(line||"").trimEnd();}).filter(Boolean);return lines.slice(-maxLines).join("\n");}
function collectorStartNotice(environmentName,environmentId,message){return`[${formatCollectorLogTimestamp(new Date())}] [${collectorLogEnvironmentLabel(environmentName,environmentId)}] ${message}`;}
function collectorTailSuggestsRunning(tail){const lines=String(tail||"").split(/\r?\n/).map(function(line){return String(line||"").trim();}).filter(Boolean);if(lines.length===0)return false;const requestPattern=/(Run Jobs Now requested|Waiting for collector startup|Starting background collector|Starting environment collector)/i;const finishPattern=/(Collector finished|Collector failed|Collector aborted)/i;let lastRequestIndex=-1;let lastFinishIndex=-1;lines.forEach(function(line,index){if(requestPattern.test(line))lastRequestIndex=index;if(finishPattern.test(line))lastFinishIndex=index;});return lastRequestIndex>=0&&lastRequestIndex>lastFinishIndex;}
function effectiveCollectorStatus(job,environmentId){const currentJob=job||{};const status=String(currentJob.status||"").trim().toLowerCase()||"idle";if(status==="running")return"running";if(collectorRefreshWindowActive(environmentId)&&collectorTailSuggestsRunning(currentJob.tail))return"running";return status;}
function optimisticCollectorStart(environmentId,environmentName,message){if(!state.dashboard)return;const currentJob=state.dashboard.job||{};const currentTail=trimCollectorTail(currentJob.tail,9);const line=collectorStartNotice(environmentName,environmentId,message);state.dashboard.job=Object.assign({},currentJob,{status:"running",startedAt:new Date().toISOString(),finishedAt:"",trigger:"manual",tail:trimCollectorTail(currentTail?`${currentTail}\n${line}`:line,10)});render();}
function applicationSectionMeta(environment){const labels=enabledProductLabels(resolvedProducts(environment));if(labels.length===1)return{label:labels[0],copy:`${labels[0]} runtime metrics and checks.`};const labelText=labels.length===2?`${labels[0]} and ${labels[1]}`:labels.length>2?`${labels.slice(0,-1).join(", ")}, and ${labels[labels.length-1]}`:"Application";return{label:"Application Metrics",copy:`${labelText} tabs.`};}
