function serverHealthSeverity(server,key){return((((server||{}).health||{}).checks||{})[key]||{}).severity||"";}
function thresholdText(limit,key){const suffix=String(key||"").toLowerCase().includes("percent")?"%":"";if(!limit||typeof limit!=="object")return"";if(limit.ge!=null)return`threshold >= ${limit.ge}${suffix}`;if(limit.le!=null)return`threshold <= ${limit.le}${suffix}`;return"";}
function healthCheckValue(check,key){const value=(check||{}).value;if(value==null||value==="")return"-";return String(key||"").toLowerCase().includes("percent")?formatPercent(value):formatValue(value,"-");}
function environmentStatusReasonItems(dashboard){const payload=dashboard||{};const server=payload.server||{};const health=server.health||{};const checks=health.checks||{};const thresholds=health.thresholds||{};const rows=[];if(server.reachable===false)rows.push({key:"Server Reachability",value:server.error||"Environment host is unreachable.",tone:"critical"});Object.keys(checks).forEach(function(key){const check=checks[key]||{};const severity=String(check.severity||"").toLowerCase();if(!["critical","warning"].includes(severity))return;const threshold=thresholdText(((thresholds[key]||{})[severity]),key);rows.push({key:check.label||startCase(key),value:`${healthCheckValue(check,key)} is ${severity}${threshold?`; ${threshold}`:""}`,tone:severity});});if(payload.collectorError)rows.push({key:"Collector",value:payload.collectorError,tone:"critical"});return rows;}
function renderEnvironmentStatusReasons(dashboard){const rows=environmentStatusReasonItems(dashboard);if(rows.length===0)return"";const status=startCase(((dashboard||{}).server||{}).health&&((dashboard||{}).server||{}).health.status||((dashboard||{}).status)||"down");return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Why Environment Is ${escapeHtml(status)}</h3><p class="panel-copy">The environment badge follows the most severe host or collector health signal in the latest snapshot.</p></div></div>${renderDefinitionList(rows)}</section>`;}
function environmentPageStatusMeta(record,overview,dashboard){const job=((dashboard||{}).job)||{};const environmentId=(record&&record.id)||((dashboard||{}).environment||{}).id||((overview||{}).id)||currentEnvironmentId();const bootstrap=(record&&record.bootstrap)||(((dashboard||{}).environment||{}).bootstrap)||{};if(effectiveCollectorStatus(job,environmentId)==="running")return{status:"configured",label:"Collecting Now"};const status=(overview||{}).status||((dashboard||{}).status)||"configured";if(status==="configured")return{status:"configured",label:bootstrap.status==="ready"?"Configured":"Waiting For First Run"};if(status==="healthy")return{status:"healthy",label:"Environment Healthy"};if(status==="warning")return{status:"warning",label:"Environment Warning"};if(status==="down")return{status:"down",label:"Environment Down"};return{status:status,label:statusLabel(status)};}
