function patchRecommendationNeedsAction(recommendation){const rec=recommendation||{};return String(rec.status||"").toLowerCase()!=="latest"||coerceList(rec.missingPatches).length>0;}
function patchRecommendationTone(recommendation){return patchRecommendationNeedsAction(recommendation)?"warning":"healthy";}
