function patchRecommendationNotice(recommendation){const rec=recommendation||{};if(!rec.message)return"";const tone=patchRecommendationTone(rec);const status=patchRecommendationStatusText(rec);const safeMessage=escapeHtml(rec.message).replace(/KA754/g,`<a class="support-link" href="${KA754_URL}" target="_blank" rel="noopener noreferrer">KA754</a>`);return`<div class="patch-status-banner is-${tone==="healthy"?"healthy":"warning"}"><div><span class="patch-status-label">${escapeHtml(status)}</span><p>${safeMessage}</p></div></div>`;}
