function renderKa754Recommendation(recommendation){const rec=recommendation||{};if(!rec.latestPatchId)return"";const components=coerceList(rec.components).join(", ")||"OIG";const needsAction=patchRecommendationNeedsAction(rec);const action=needsAction?"Review Oracle KM KA754 and apply latest SPB":"Latest Stack Patch Bundle applied";const kaLink=`<a class="support-link" href="${KA754_URL}" target="_blank" rel="noopener noreferrer">KA754</a>`;const safeComponents=escapeHtml(components);const safeVersion=escapeHtml(rec.version||"");const safeRelease=escapeHtml(rec.latestRelease||"-");const safePatch=escapeHtml(rec.latestPatchId);const detail=needsAction?`Please review Oracle KM document ${kaLink} and apply the latest available ${safeVersion} Stack Patch Bundle for ${safeComponents}, currently ${safeRelease} Patch ${safePatch}.`:`Installed patches match the latest Stack Patch Bundle level documented in ${kaLink} for ${safeComponents}: ${safeRelease} Patch ${safePatch}.`;const tone=needsAction?"warning":"healthy";return`<div class="subsection-block patch-recommendation-block is-${tone==="healthy"?"healthy":"warning"}"><h4>Oracle KM KA754 Patch Recommendation</h4>${renderDefinitionList([{key:"Patch Status",htmlValue:renderStatusPill(tone==="healthy"?"healthy":"warning",patchRecommendationStatusText(rec)),tone:tone},{key:"Action",value:action,tone:tone},{key:"Component",value:components},{key:"Base Version",value:rec.version||"-"},{key:"Recommended Patch",value:`${rec.latestPatchId} - ${rec.latestRelease||"Latest SPB"}`,tone:tone},{key:"Recommendation",htmlValue:detail,tone:tone}])}</div>`;}
function renderOpatchInventoryPanel(opatch,title,copy){const inventory=opatch||{};const versions=coerceList(inventory.versions);const distributions=coerceList(inventory.distributions);const products=coerceList(inventory.products);const patches=coerceList(inventory.patches);const recommendation=inventory.recommendation||{};const comparisonRows=coerceList(inventory.patchComparisonRows).length?coerceList(inventory.patchComparisonRows):coerceList(recommendation.comparisonRows);const rows=comparisonRows.length?comparisonRows:patches.map(function(item){const row=Object.assign({},item);row.recommendation="-";row.recommendationStatus="none";return row;});const versionItems=versions.map(function(item){return{key:item.key||"Version",value:item.value||"-"};});distributions.forEach(function(value,index){versionItems.push({key:index?"OUI Distribution "+(index+1):"OUI Distribution",value:value});});if(inventory.durationSeconds)versionItems.push({key:"OPatch Duration",value:`${inventory.durationSeconds} sec`});const productRows=products.length?`<div class="table-wrap"><table><thead><tr><th>Installed Product</th><th>Version</th></tr></thead><tbody>${products.map(function(item){return`<tr><td>${escapeHtml(item.name||"-")}</td><td>${escapeHtml(item.version||"-")}</td></tr>`;}).join("")}</tbody></table></div>`:"";const patchRows=rows.length?`<div class="table-wrap"><table><thead><tr><th>Patch</th><th>Description</th><th>Applied On</th><th>Recommended</th></tr></thead><tbody>${rows.map(function(item){return`<tr class="patch-row is-${escapeHtml(String(item.recommendationStatus||"none").toLowerCase())}"><td>${escapeHtml(item.patchId||"-")}</td><td>${escapeHtml(item.description||"-")}</td><td>${escapeHtml(item.appliedOn||"-")}</td><td>${patchRecommendationCell(item)}</td></tr>`;}).join("")}</tbody></table></div>`:renderEmptyPanel("No OPatch rows",inventory.error||"No installed interim patches were returned by OPatch lsinventory.");return`<section class="panel patch-inventory-panel"><div class="panel-header"><div><h3 class="panel-title">${escapeHtml(title)}</h3><p class="panel-copy">${escapeHtml(copy)}</p></div></div>${inventory.error?`<p class="table-note">${escapeHtml(inventory.error)}</p>`:""}${inventory.warning?`<p class="table-note">${escapeHtml(inventory.warning)}</p>`:""}${patchRecommendationNotice(recommendation)}${renderKa754Recommendation(recommendation)}${versionItems.length?renderDefinitionList(versionItems):""}${productRows}${patchRows}${inventory.command?`<p class="table-note">Command: ${escapeHtml(inventory.command)}</p>`:""}${inventory.distributionCommand?`<p class="table-note">Distribution command: ${escapeHtml(inventory.distributionCommand)}</p>`:""}</section>`;}
