function opatchVersionValue(inventory,label){const wanted=String(label||"").toLowerCase();const row=coerceList((inventory||{}).versions).find(function(item){return String(item.key||"").toLowerCase()===wanted;});return(row||{}).value||"";}
function opatchDetectedVersion(inventory,recommendation){const rec=recommendation||{};const products=coerceList((inventory||{}).products);const distributions=coerceList((inventory||{}).distributions);const components=coerceList(rec.components).map(function(item){return String(item||"").toUpperCase();});let product=products.find(function(item){const name=String(item.name||"").toUpperCase();return components.some(function(component){return name.includes(component)||component==="OIG"&&name.includes("IDENTITY")||component==="OID"&&name.includes("INTERNET DIRECTORY")||component==="OUD"&&name.includes("UNIFIED DIRECTORY");});});if(product&&product.version)return product.version;const distribution=distributions.find(function(item){const text=String(item||"").toUpperCase();return components.some(function(component){return text.includes(component)||component==="OID"&&text.includes("INTERNET DIRECTORY")||component==="OUD"&&text.includes("UNIFIED DIRECTORY")||component==="OIG"&&text.includes("IDENTITY");});})||distributions[0]||"";const match=String(distribution).match(/\b\d{2}\.\d(?:\.\d+){1,4}\b/);return(match||[])[0]||rec.version||"-";}
function renderOpatchCurrentLevel(inventory,recommendation){const rec=recommendation||{};const currentVersion=opatchDetectedVersion(inventory,rec);const opatchVersion=opatchVersionValue(inventory,"OPatch version")||opatchVersionValue(inventory,"OPatch Installer Version")||"-";const ouiVersion=opatchVersionValue(inventory,"OUI version")||"-";const recommended=rec.latestPatchId?`${rec.latestPatchId} - ${rec.latestRelease||"Latest SPB"}`:"-";const source=rec.catalogSource&&rec.catalogSource!=="bundled"?"Patch catalog file":"Bundled catalog";const tone=patchRecommendationNeedsAction(rec)?"warning":"healthy";return`<div class="opatch-current-strip is-${tone}"><div class="opatch-current-card"><span>Current Version</span><strong>${escapeHtml(currentVersion)}</strong></div><div class="opatch-current-card"><span>Current OPatch</span><strong>${escapeHtml(opatchVersion)}</strong></div><div class="opatch-current-card"><span>Current OUI</span><strong>${escapeHtml(ouiVersion)}</strong></div><div class="opatch-current-card"><span>Recommended Level</span><strong>${escapeHtml(recommended)}</strong></div><div class="opatch-current-card"><span>Catalog</span><strong>${escapeHtml(source)}</strong></div></div>`;}
function renderOpatchInventoryPanel(opatch,title,copy){const inventory=opatch||{};const versions=coerceList(inventory.versions);const distributions=coerceList(inventory.distributions);const products=coerceList(inventory.products);const patches=coerceList(inventory.patches);const recommendation=inventory.recommendation||{};const comparisonRows=coerceList(inventory.patchComparisonRows).length?coerceList(inventory.patchComparisonRows):coerceList(recommendation.comparisonRows);const rows=comparisonRows.length?comparisonRows:patches.map(function(item){const row=Object.assign({},item);row.recommendation="-";row.recommendationStatus="none";return row;});const versionItems=versions.map(function(item){return{key:item.key||"Version",value:item.value||"-"};});distributions.forEach(function(value,index){versionItems.push({key:index?"OUI Distribution "+(index+1):"OUI Distribution",value:value});});if(inventory.durationSeconds)versionItems.push({key:"OPatch Duration",value:`${inventory.durationSeconds} sec`});const productRows=products.length?`<div class="table-wrap"><table><thead><tr><th>Installed Product</th><th>Version</th></tr></thead><tbody>${products.map(function(item){return`<tr><td>${escapeHtml(item.name||"-")}</td><td>${escapeHtml(item.version||"-")}</td></tr>`;}).join("")}</tbody></table></div>`:"";const patchRows=rows.length?`<div class="table-wrap"><table><thead><tr><th>Patch</th><th>Description</th><th>Applied On</th><th>Recommended</th></tr></thead><tbody>${rows.map(function(item){return`<tr class="patch-row is-${escapeHtml(String(item.recommendationStatus||"none").toLowerCase())}"><td>${escapeHtml(item.patchId||"-")}</td><td>${escapeHtml(item.description||"-")}</td><td>${escapeHtml(item.appliedOn||"-")}</td><td>${patchRecommendationCell(item)}</td></tr>`;}).join("")}</tbody></table></div>`:renderEmptyPanel("No OPatch rows",inventory.error||"No installed interim patches were returned by OPatch lsinventory.");return`<section class="panel patch-inventory-panel"><div class="panel-header"><div><h3 class="panel-title">${escapeHtml(title)}</h3><p class="panel-copy">${escapeHtml(copy)}</p></div></div>${inventory.error?`<p class="table-note">${escapeHtml(inventory.error)}</p>`:""}${inventory.warning?`<p class="table-note">${escapeHtml(inventory.warning)}</p>`:""}${renderOpatchCurrentLevel(inventory,recommendation)}${patchRecommendationNotice(recommendation)}${renderKa754Recommendation(recommendation)}${versionItems.length?renderDefinitionList(versionItems):""}${productRows}${patchRows}${inventory.command?`<p class="table-note">Command: ${escapeHtml(inventory.command)}</p>`:""}${inventory.distributionCommand?`<p class="table-note">Distribution command: ${escapeHtml(inventory.distributionCommand)}</p>`:""}</section>`;}
