function renderOaaMetricSection(title,count,body,command){return`<section class="metric-static-section"><div class="metric-static-header"><span>${escapeHtml(title)}</span><strong>${escapeHtml(formatValue(count,"0"))}</strong></div><div class="metric-static-body">${body}${command?`<p class="table-note">Command: ${escapeHtml(command)}</p>`:""}</div></section>`;}
function oaaToneForValue(value){const text=String(value||"").trim().toLowerCase();if(!text||text==="-")return"configured";if(/failed|error|crash|down|unavailable/.test(text))return"down";if(/warning|pending|terminating|unknown|0\/|notready/.test(text))return"warning";if(/running|ready|deployed|available|complete|active|1\/1|true|clusterip|nodeport/.test(text))return"healthy";return"configured";}
function renderOaaStatusPill(value,label){const text=formatValue(label||value,"-");return renderStatusPill(oaaToneForValue(value),text);}
function oaaServiceLabel(name){const cleaned=String(name||"").replace(/^(oaainstall|oaamgmt)-/i,"").replace(/-[a-f0-9]{8,10}-[a-z0-9]{4,6}$/i,"").replace(/-/g," ").trim();return cleaned?cleaned.replace(/\b(oaa|sms|totp|yotp|fido|kba|drss|spui|ui|cc)\b/gi,function(token){return token.toUpperCase();}).replace(/\b\w/g,function(c){return c.toUpperCase();}):formatValue(name,"Pod");}
function renderOaaMetricStats(items){return`<div class="oaa-visual-stats">${items.map(function(item){const tone=metricToneName(item.tone);return`<div class="oaa-visual-stat${tone?` is-${tone}`:""}"><span>${escapeHtml(item.label||"")}</span><strong>${escapeHtml(formatValue(item.value,"-"))}</strong></div>`;}).join("")}</div>`;}
function renderOaaPodsPanel(pods,namespace,emptyCopy){const rows=coerceList(pods);const ns=namespace||"oaans";const running=rows.filter(function(row){return String(row.status||"").toLowerCase()==="running";}).length;const ready=rows.filter(function(row){return String(row.ready||"").trim().split("/")[0]===String(row.ready||"").trim().split("/")[1]&&String(row.ready||"").includes("/");}).length;const restartTotal=rows.reduce(function(total,row){return total+(parseInt(row.restarts,10)||0);},0);const nodes=uniqueList(rows.map(function(row){return row.node||"";}));return`<section class="panel oaa-visual-panel"><div class="panel-header"><div><h3 class="panel-title">OAA Pods</h3><p class="panel-copy">Pod readiness from namespace ${escapeHtml(ns)}, grouped as service cards for quick health review.</p></div></div>${rows.length===0?renderEmptyPanel("No OAA pods",emptyCopy):`${renderOaaMetricStats([{label:"Pods",value:rows.length,tone:rows.length?"ok":""},{label:"Running",value:running,tone:running===rows.length?"ok":"warning"},{label:"Ready",value:ready,tone:ready===rows.length?"ok":"warning"},{label:"Restarts",value:restartTotal,tone:restartTotal>0?"warning":"ok"},{label:"Nodes",value:nodes.length,tone:"ok"}])}<div class="oaa-pod-grid">${rows.map(function(row){const tone=metricToneName(oaaToneForValue(row.status));return`<article class="oaa-pod-card${tone?` is-${tone}`:""}"><div class="oaa-pod-card-head"><div><h4>${escapeHtml(oaaServiceLabel(row.name))}</h4><p>${escapeHtml(formatValue(row.name,"-"))}</p></div>${renderOaaStatusPill(row.status)}</div><div class="oaa-pod-meta"><span><small>Ready</small><strong>${escapeHtml(formatValue(row.ready,"-"))}</strong></span><span><small>Restarts</small><strong>${escapeHtml(formatValue(row.restarts,"0"))}</strong></span><span><small>Age</small><strong>${escapeHtml(formatValue(row.age,"-"))}</strong></span></div><div class="oaa-pod-foot"><span>${escapeHtml(formatValue(row.node,"-"))}</span><span>${escapeHtml(formatValue(row.podIp,"-"))}</span></div></article>`;}).join("")}</div>`}</section>`;}
function renderOaaResourceGroups(rows,emptyCopy){const items=coerceList(rows);if(items.length===0)return renderEmptyPanel("No resources",emptyCopy);const order=["Pod","Service","Deployment","ReplicaSet","Ingress","PersistentVolumeClaim"];const kinds=uniqueList(order.concat(items.map(function(row){return row.kind||"Other";}))).filter(function(kind){return items.some(function(row){return String(row.kind||"Other")===kind;});});return`<div class="oaa-resource-board">${kinds.map(function(kind){const group=items.filter(function(row){return String(row.kind||"Other")===kind;});return`<section class="oaa-resource-group"><div class="oaa-resource-group-head"><span>${escapeHtml(kind==="PersistentVolumeClaim"?"PVC":kind)}</span><strong>${escapeHtml(group.length)}</strong></div><div class="oaa-resource-list">${group.map(function(row){return`<div class="oaa-resource-row"><div class="oaa-resource-main"><strong>${escapeHtml(formatValue(row.name,"-"))}</strong><span>${escapeHtml(formatValue(row.endpoint,"-"))}</span></div><div class="oaa-resource-state">${renderOaaStatusPill(row.detail||row.ready||row.kind,row.detail||row.ready||"-")}<span class="oaa-resource-age">${escapeHtml(formatValue(row.age,"-"))}</span></div></div>`;}).join("")}</div></section>`;}).join("")}</div>`;}
function renderOaaInstallConfigGroups(rows,error,command){const items=coerceList(rows);if(items.length===0)return`${renderEmptyPanel("No install configuration",error||"No installOAA.properties values were parsed.")}${command?`<p class="table-note">Command: ${escapeHtml(command)}</p>`:""}`;const categories=uniqueList(items.map(function(row){return row.category||"Other";}));return`<div class="oaa-config-grid">${categories.map(function(category){const group=items.filter(function(row){return String(row.category||"Other")===category;});return`<section class="oaa-config-group"><div class="oaa-config-group-head"><h4>${escapeHtml(category)}</h4><span>${escapeHtml(group.length)}</span></div><div class="oaa-config-list">${group.map(function(row){return`<div class="oaa-config-row"><div><strong>${escapeHtml(formatValue(row.label||row.name,"-"))}</strong><span>${escapeHtml(formatValue(row.name,"-"))}</span></div><em>${escapeHtml(formatValue(row.value,"-"))}</em></div>`;}).join("")}</div></section>`;}).join("")}</div>${command?`<p class="table-note">Command: ${escapeHtml(command)}</p>`:""}`;}
function oaaResourceRowsByKind(rows,kind){return coerceList(rows).filter(function(row){return String((row||{}).kind||"").toLowerCase()===String(kind||"").toLowerCase();});}
function renderOaaHelmVersionBody(helmVersion,metrics){const info=helmVersion||{};const rows=[{key:"Helm Version",value:info.version||"-"},{key:"Git Commit",value:info.gitCommit||"-"},{key:"Git Tree State",value:info.gitTreeState||"-"},{key:"Go Version",value:info.goVersion||"-"}];const warnings=coerceList(info.warnings);if(!(info.version||info.gitCommit||info.goVersion||info.raw))return renderEmptyPanel("No Helm version",metrics.helmVersionError||"helm version did not return details.");return`${renderCompactDefinitionGrid(rows,"oaa-profile-grid")}${warnings.length?`<p class="table-note">${escapeHtml(warnings.join(" "))}</p>`:""}`;}
function renderOaaDeploymentDetails(metrics){const details=coerceList(metrics.deploymentDetails);const statusRows=coerceList(metrics.installationStatus);return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">OAA Deployment Details</h3><p class="panel-copy">Deployment endpoints and installation status printed from the OAA management pod when available.</p></div></div>${details.length===0?renderEmptyPanel("No deployment details",metrics.deploymentDetailsError||"No printOAADetails.sh output was returned."):`${renderCompactDefinitionGrid(details.map(function(item){return{key:item.name,value:item.value};}),"oaa-deployment-grid")}${metrics.deploymentDetailsCommand?`<p class="table-note">Command: ${escapeHtml(metrics.deploymentDetailsCommand)}</p>`:""}`}${statusRows.length?`<div class="subsection-block"><h4>Management status.info</h4>${renderCompactDefinitionGrid(statusRows.map(function(item){return{key:item.name,value:item.value};}),"oaa-deployment-grid")}${metrics.installationStatusCommand?`<p class="table-note">Command: ${escapeHtml(metrics.installationStatusCommand)}</p>`:""}</div>`:metrics.installationStatusError?`<p class="table-note">${escapeHtml(metrics.installationStatusError)}</p>`:""}</section>`;}
function renderOaaInstallConfig(metrics){const rows=coerceList(metrics.installConfig);return`<section class="panel oaa-visual-panel"><div class="panel-header"><div><h3 class="panel-title">OAA Install Configuration</h3><p class="panel-copy">Deployment, ingress, database, OAuth, vault, LDAP, TAP, and factor settings grouped by category from installOAA.properties.</p></div></div>${renderOaaInstallConfigGroups(rows,metrics.installConfigError,metrics.installConfigCommand)}</section>`;}
function renderOaaDatabaseInfo(metrics){const db=metrics.database||{};const hasDatabase=[db.host,db.port,db.schema,db.service,db.name].some(function(value){return String(value||"").trim();});const passwordStatus=db.hasPassword?"Password entry found in installOAA.properties. The value is not displayed.":"DB password was not found in installOAA.properties. Table-level database checks should prompt for the schema password when enabled.";const rows=[{key:"Database Host",value:db.host||"-"},{key:"Database Port",value:db.port||"-"},{key:"Database Service",value:db.service||"-"},{key:"Database Name",value:db.name||"-"},{key:"Database Schema",value:db.schema||"-"},{key:"Tablespace",value:db.tablespace||"-"},{key:"Protocol",value:db.protocol||"-"},{key:"Create Schema",value:db.createSchema||"-"},{key:"Schema Password",value:passwordStatus}];return`<section class="panel oaa-visual-panel"><div class="panel-header"><div><h3 class="panel-title">OAA Database Info</h3><p class="panel-copy">Database connection metadata derived from installOAA.properties. Secret values stay hidden.</p></div></div>${hasDatabase?renderDefinitionList(rows):renderEmptyPanel("No database metadata",metrics.installConfigError||"Database keys were not found in installOAA.properties.")}</section>`;}
function renderOaaSchemaTables(metrics){const rows=coerceList(metrics.schemaTables);const summary=metrics.schemaTableSummary||{};const error=metrics.schemaTablesError;const command=String(metrics.schemaTablesCommand||"");const commandNote=command&&command.length<500?`<p class="table-note">Collector: ${escapeHtml(command)}</p>`:"";const totalRows=rows.reduce(function(total,row){const value=parseInt(row.rowCount,10);return total+(Number.isFinite(value)?value:0);},0);const cards=renderSummaryTiles([{label:"Tables Checked",value:summary.checkedTables||rows.length||0,copy:"Important OAA/OARM schema tables selected for customer-facing checks."},{label:"Available",value:summary.availableTables||rows.filter(function(row){return row.rowCount!=null;}).length||0,copy:"Tables that responded to row-count checks."},{label:"Total Rows",value:summary.totalRows||totalRows||0,copy:"Combined row count across available tables."},{label:"DB User",value:summary.databaseUser||((metrics.database||{}).username)||((metrics.database||{}).schema)||"-",copy:"Database schema used for the on-demand query."}]);return`<section class="panel oaa-visual-panel"><div class="panel-header"><div><h3 class="panel-title">OAA Schema Tables</h3><p class="panel-copy">On-demand table counts from the configured OAA/OARM schema. Password is requested only for this load and is not stored. <a class="support-link" href="${OAA_SCHEMA_REFERENCE_DOC_URL}" target="_blank" rel="noopener">Oracle schema reference</a></p></div></div>${error?`<div class="alert-card is-warning"><strong>Schema query warning</strong><p>${escapeHtml(error)}</p></div>`:""}${rows.length===0?renderEmptyPanel("Schema tables not loaded","Select Schema Tables and click Load. If database details are missing, the dashboard prompts for host, service, schema, and password."):cards+`<div class="table-wrap"><table><thead><tr><th>Area</th><th>Table</th><th>Rows</th><th>Status</th><th>Why It Matters</th><th>Message</th></tr></thead><tbody>${rows.map(function(row){const status=String(row.status||"").toLowerCase();const tone=status==="available"?"healthy":status==="unavailable"?"warning":"configured";return`<tr><td>${escapeHtml(row.area||"-")}</td><td><strong>${escapeHtml(row.name||"-")}</strong></td><td>${escapeHtml(row.rowCount==null?"-":row.rowCount)}</td><td>${renderStatusPill(tone,row.status||"-")}</td><td>${escapeHtml(row.purpose||"-")}</td><td>${escapeHtml(row.message||"-")}</td></tr>`;}).join("")}</tbody></table></div>${commandNote}`}</section>`;}
function renderOaaCertificates(metrics){const rows=coerceList(metrics.certificates);const error=metrics.certificateError;return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">OAA HTTPS Certificates</h3><p class="panel-copy">Certificate names and expiry dates collected from the configured OAA HTTPS endpoints.</p></div></div>${rows.length===0?renderEmptyPanel("No OAA certificates",error||"No HTTPS OAA endpoint certificates were returned."):`<div class="table-wrap"><table><thead><tr><th>Endpoint</th><th>Host</th><th>Subject</th><th>Issuer</th><th>Expires</th><th>Status</th></tr></thead><tbody>${rows.map(function(item){const status=String(item.status||"healthy");const pillState=status==="expired"?"down":status==="warning"?"warning":"healthy";return`<tr><td>${escapeHtml(item.server||item.url||"-")}</td><td>${escapeHtml(`${formatValue(item.host,"-")}:${formatValue(item.port,"443")}`)}</td><td>${escapeHtml(item.subject||"-")}</td><td>${escapeHtml(item.issuer||"-")}</td><td>${escapeHtml(item.expiresAt||"-")}</td><td>${renderStatusPill(pillState,item.statusLabel||startCase(status))}</td></tr>`;}).join("")}</tbody></table></div>${error?`<p class="table-note">${escapeHtml(error)}</p>`:""}`}</section>`;}
function renderOaaProfilePanel(record,metrics,oaa,kubeHost){const database=metrics.database||{};const databaseValue=[database.host, database.port?`:${database.port}`:"", database.service?`/${database.service}`:"", database.schema?` schema ${database.schema}`:""].filter(Boolean).join("")||"-";return`<section class="panel oaa-profile-panel"><div class="panel-header"><div><h3 class="panel-title">Saved OAA Profile</h3><p class="panel-copy">Kubernetes, runtime, database, and SSH settings saved or derived for this connection.</p></div></div>${renderCompactDefinitionGrid([{key:"Install Settings Path",value:oaa.installSettingsPath||metrics.installSettingsPath||"-"},{key:"OAA Namespace",value:oaa.namespace||metrics.namespace||"oaans"},{key:"Ingress Namespace",value:oaa.ingressNamespace||metrics.ingressNamespace||"ingressns"},{key:"Release Name",value:oaa.releaseName||metrics.releaseName||"oaainstall"},{key:"Runtime Base URL",value:oaa.runtimeBaseUrl||metrics.runtimeBaseUrl||"-"},{key:"Runtime API Username",value:oaa.runtimeUsername||metrics.runtimeUsername||"-"},{key:"Database",value:databaseValue},{key:"Kubernetes Host",value:kubeHost.host||((record.server||{}).host)||"-"},{key:"Kubernetes SSH Mode",value:sshModeLabel(resolveSshMode(kubeHost.host?kubeHost:(record.server||{})))}],"oaa-profile-grid")}</section>`;}
function renderOaaDiagnostics(metrics){const issues=[];if(metrics.error)issues.push({key:"Collector Error",value:metrics.error,tone:"warning"});if(metrics.podsError)issues.push({key:"Pods",value:metrics.podsError,tone:"warning"});if(metrics.namespaceResourcesError)issues.push({key:"OAA Namespace Resources",value:metrics.namespaceResourcesError,tone:"warning"});if(metrics.nodesError)issues.push({key:"Kubernetes Nodes",value:metrics.nodesError,tone:"warning"});if(metrics.helmError)issues.push({key:"Helm Releases",value:metrics.helmError,tone:"warning"});if(metrics.podUsageError)issues.push({key:"Pod Resource Usage",value:metrics.podUsageError,tone:"warning"});if(metrics.nodeUsageError)issues.push({key:"Node Resource Usage",value:metrics.nodeUsageError,tone:"warning"});if(metrics.eventsError)issues.push({key:"Warning Events",value:metrics.eventsError,tone:"warning"});if(metrics.ingressError)issues.push({key:"Ingress / Services",value:metrics.ingressError,tone:"warning"});if(metrics.deploymentDetailsError)issues.push({key:"Deployment Details",value:metrics.deploymentDetailsError,tone:"warning"});if(metrics.installConfigError)issues.push({key:"Install Configuration",value:metrics.installConfigError,tone:"warning"});if(metrics.installationStatusError)issues.push({key:"Management status.info",value:metrics.installationStatusError,tone:"warning"});if(metrics.certificateError)issues.push({key:"OAA Certificates",value:metrics.certificateError,tone:"warning"});if(metrics.propertiesError)issues.push({key:"Runtime Properties",value:metrics.propertiesError,tone:"warning"});if(metrics.describeError)issues.push({key:"Pod Describe",value:metrics.describeError,tone:"warning"});if(metrics.logError)issues.push({key:"Pod Logs",value:metrics.logError,tone:"warning"});if(metrics.managementLogError)issues.push({key:"Management Logs",value:metrics.managementLogError,tone:"warning"});const commands=coerceList(metrics.commands).filter(function(item){return item&&item.command;}).map(function(item){return{key:item.label||"Command",value:item.command};});return`<section class="panel oaa-diagnostics-panel"><div class="panel-header"><div><h3 class="panel-title">Collection Diagnostics</h3><p class="panel-copy">Why data may be missing and which commands the collector is using.</p></div></div>${issues.length?renderDefinitionList(issues):`<p class="table-note">No OAA collection errors were reported in the latest snapshot.</p>`}${commands.length?`<div class="diagnostic-command-list">${renderCompactDefinitionGrid(commands,"diagnostic-command-grid")}</div>`:""}</section>`;}
function renderOaaHelmHistoryBody(rows,metrics){const items=coerceList(rows);if(items.length===0)return renderEmptyPanel("No Helm history",metrics.helmHistoryError||"No helm history rows were returned.");return`${renderRuntimeMetricTable(items,[{key:"release",label:"Release"},{key:"revision",label:"Revision"},{key:"updated",label:"Updated"},{key:"status",label:"Status"},{key:"chart",label:"Chart"},{key:"appVersion",label:"App Version"},{key:"description",label:"Description"}],"No Helm history","No helm history rows were returned.")}${coerceList(metrics.helmHistoryWarnings).length?`<p class="table-note">${escapeHtml(coerceList(metrics.helmHistoryWarnings).join(" "))}</p>`:""}`;}
function renderOaaServerMetrics(metrics){const nodes=coerceList(metrics.nodeInventory);const nodeUsage=coerceList(metrics.nodeResourceUsage);const podUsage=coerceList(metrics.podResourceUsage);const warningEvents=coerceList(metrics.warningEvents);const namespaceResources=coerceList(metrics.namespaceResources);const helmReleases=coerceList(metrics.helmReleases);const helmHistory=coerceList(metrics.helmHistory);const helmVersion=metrics.helmVersion||{};const resourceColumns=[{key:"name",label:"Name"},{key:"ready",label:"Ready / Volume"},{key:"detail",label:"Status / Type"},{key:"endpoint",label:"Endpoint / Capacity"},{key:"age",label:"Age"}];const resourceSections=[{kind:"Service",label:"Services"},{kind:"Deployment",label:"Deployments"},{kind:"ReplicaSet",label:"ReplicaSets"},{kind:"Ingress",label:"Ingress"},{kind:"PersistentVolumeClaim",label:"Persistent Volume Claims"}].map(function(item){const rows=oaaResourceRowsByKind(namespaceResources,item.kind);return rows.length?renderOaaMetricDisclosure(item.label,rows.length,renderRuntimeMetricTable(rows,resourceColumns,`No ${item.label}`,`No ${item.label} rows were returned by kubectl.`),"",false):"";}).join("");const knownKinds=new Set(["service","deployment","replicaset","ingress","persistentvolumeclaim"]);const otherResources=namespaceResources.filter(function(row){return!knownKinds.has(String((row||{}).kind||"").toLowerCase());});const otherSection=otherResources.length?renderOaaMetricDisclosure("Other Namespace Resources",otherResources.length,renderRuntimeMetricTable(otherResources,[{key:"kind",label:"Kind"}].concat(resourceColumns),"No other resources","No other namespace resources were returned."),"",false):"";const usageSections=[nodeUsage.length?renderOaaMetricDisclosure("Node Resource Usage",nodeUsage.length,renderRuntimeMetricTable(nodeUsage,[{key:"name",label:"Node"},{key:"cpu",label:"CPU"},{key:"cpuPercent",label:"CPU %"},{key:"memory",label:"Memory"},{key:"memoryPercent",label:"Memory %"}],"No node usage","kubectl top nodes returned no rows."),metrics.nodeUsageCommand,false):"",podUsage.length?renderOaaMetricDisclosure("Pod Resource Usage",podUsage.length,renderRuntimeMetricTable(podUsage,[{key:"name",label:"Pod"},{key:"cpu",label:"CPU"},{key:"memory",label:"Memory"}],"No pod usage","kubectl top pods returned no rows."),metrics.podUsageCommand,false):""].join("");const warningSection=warningEvents.length?renderOaaMetricDisclosure("Recent Warning Events",warningEvents.length,renderRuntimeMetricTable(warningEvents,[{key:"type",label:"Type"},{key:"reason",label:"Reason"},{key:"object",label:"Object"},{key:"message",label:"Message"},{key:"count",label:"Count"},{key:"age",label:"Age"}],"No warning events","No Warning events were returned for the OAA namespace."),metrics.eventsCommand,false):"";return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">OAA Server Metrics</h3><p class="panel-copy">Helm version, Kubernetes node inventory, Helm releases, and release history are shown directly. Expand namespace resources, usage, and warning events only when you need the detail.</p></div></div>${renderOaaMetricSection("Helm Version",helmVersion.version?1:0,renderOaaHelmVersionBody(helmVersion,metrics),metrics.helmVersionCommand)}${renderOaaMetricSection("Kubernetes Nodes",nodes.length,nodes.length?renderRuntimeMetricTable(nodes,[{key:"name",label:"Node"},{key:"status",label:"Status"},{key:"roles",label:"Roles"},{key:"internalIp",label:"Internal IP"},{key:"hostname",label:"Hostname"},{key:"osImage",label:"OS Image"},{key:"kernelVersion",label:"Kernel Version"},{key:"kubeletVersion",label:"Kubelet"},{key:"containerRuntime",label:"Container Runtime"},{key:"cpu",label:"CPU"},{key:"memory",label:"Memory"},{key:"age",label:"Age"}],"No Kubernetes nodes",metrics.nodesError||"No Kubernetes nodes were returned by kubectl."):renderEmptyPanel("No Kubernetes nodes",metrics.nodesError||"No Kubernetes nodes were returned by kubectl."),metrics.nodesCommand)}${renderOaaMetricSection("Helm Releases",helmReleases.length,helmReleases.length?renderRuntimeMetricTable(helmReleases,[{key:"name",label:"Release"},{key:"namespace",label:"Namespace"},{key:"revision",label:"Revision"},{key:"status",label:"Status"},{key:"chart",label:"Chart"},{key:"appVersion",label:"App Version"},{key:"updated",label:"Updated"}],"No Helm releases",metrics.helmError||"No Helm releases were returned from the OAA management pod."):renderEmptyPanel("No Helm releases",metrics.helmError||"No Helm releases were returned from the OAA management pod."),metrics.helmCommand)}${renderOaaMetricSection("Helm History",helmHistory.length,renderOaaHelmHistoryBody(helmHistory,metrics),metrics.helmHistoryCommand)}${resourceSections||otherSection?renderOaaMetricDisclosure("OAA Namespace Resources",namespaceResources.length,`<div class="metric-disclosure-stack">${resourceSections}${otherSection}</div>`,metrics.namespaceResourcesCommand,false):""}${usageSections}${warningSection}</section>`;}
function renderOaaMetrics(record,dashboard){
const metrics=((dashboard.productMetrics||{}).oaa)||{};
const oaa=(record.oaa||{});
const kubeHost=oaa.kubeHost||{};
const pods=coerceList(metrics.pods);
const resources=coerceList(metrics.ingressResources);
const properties=coerceList(metrics.properties);
const specificProperties=coerceList(metrics.specificProperties);
const nodeInventory=coerceList(metrics.nodeInventory);
const warningEvents=coerceList(metrics.warningEvents);
const certificates=coerceList(metrics.certificates);
const podCount=parseInt(metrics.podCount,10)||pods.length||0;
const readyPodCount=parseInt(metrics.readyPodCount,10)||0;
const runningPodCount=parseInt(metrics.runningPodCount,10)||0;
const restartCount=parseInt(metrics.restartCount,10)||0;
const nodeCount=parseInt(metrics.nodeCount,10)||nodeInventory.length||0;
const warningEventCount=parseInt(metrics.warningEventCount,10)||warningEvents.length||0;
const installConfigCount=parseInt(metrics.installConfigCount,10)||coerceList(metrics.installConfig).length||0;
const loaded=selectedOaaMetricGroups();
const sections=[];
const emptyPodCopy=metrics.error||metrics.podsError||"No pods were returned by kubectl.";
if(loaded.includes("pods"))sections.push(renderOaaPodsPanel(pods,metrics.namespace||oaa.namespace||"oaans",emptyPodCopy));
if(loaded.includes("serverMetrics"))sections.push(renderOaaServerMetrics(metrics));
if(loaded.includes("ingress"))sections.push(`<section class="panel oaa-visual-panel"><div class="panel-header"><div><h3 class="panel-title">Ingress / Services</h3><p class="panel-copy">Ingress namespace resources grouped by Kubernetes kind from ${escapeHtml(metrics.ingressNamespace||oaa.ingressNamespace||"ingressns")}.</p></div></div>${renderOaaResourceGroups(resources,metrics.error||metrics.ingressError||"No ingress namespace resources were returned by kubectl.")}</section>`);
if(loaded.includes("installConfig"))sections.push(renderOaaInstallConfig(metrics));
if(loaded.includes("databaseInfo"))sections.push(renderOaaDatabaseInfo(metrics));
if(loaded.includes("schemaTables"))sections.push(renderOaaSchemaTables(metrics));
if(loaded.includes("certificates"))sections.push(renderOaaCertificates(metrics));
if(loaded.includes("specificProperties"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Specific Properties</h3><p class="panel-copy">Configured property-name lookups from the OAA runtime API.</p></div></div>${renderOaaPropertiesTable(specificProperties,"No specific properties",metrics.propertiesError||metrics.error||"No specific property values were returned.")}</section>`);
if(loaded.includes("podDescribe"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Pod Describe</h3><p class="panel-copy">kubectl describe output for ${escapeHtml(metrics.describePodName||"the selected OAA pod")}.</p></div></div>${renderTerminalSnippet(metrics.describeOutput,metrics.describeError||metrics.error||"No describe output was returned.",false)}</section>`);
if(loaded.includes("podLogs"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Pod Logs</h3><p class="panel-copy">Recent kubectl logs output for ${escapeHtml(metrics.logPodName||"the selected OAA pod")} and management install logs when available.</p></div></div><div class="subsection-block"><h4>Container Logs</h4>${renderTerminalSnippet(metrics.logOutput,metrics.logError||metrics.error||"No log output was returned.",false)}</div><div class="subsection-block"><h4>Management Logs</h4>${renderTerminalSnippet(metrics.managementLogOutput,metrics.managementLogError||"No management log output was returned.",false)}${metrics.managementLogCommand?`<p class="table-note">Command: ${escapeHtml(metrics.managementLogCommand)}</p>`:""}</div></section>`);
if(loaded.includes("properties"))sections.push(renderOaaRuntimePropertiesPanel(properties,metrics));
if(loaded.includes("deploymentDetails"))sections.push(renderOaaDeploymentDetails(metrics));
const metricBody=sections.join("")||renderEmptyPanel("No metric groups selected","Select one or more OAA metric groups and click Load.");
return`<div class="content-stack">${renderSummaryTiles([{label:"Pods",value:formatValue(podCount,"0"),copy:"OAA pods returned by kubectl."},{label:"Ready Pods",value:formatValue(readyPodCount,"0"),copy:"Pods with all containers ready and Running."},{label:"Running Pods",value:formatValue(runningPodCount,"0"),copy:"Pods currently reporting Running."},{label:"Restarts",value:formatValue(restartCount,"0"),copy:"Total container restarts across OAA pods."},{label:"Kubernetes Nodes",value:formatValue(nodeCount,"0"),copy:"Cluster nodes visible from kubectl."},{label:"Warning Events",value:formatValue(warningEventCount,"0"),copy:"Recent Warning events in the OAA namespace."},{label:"Install Config",value:formatValue(installConfigCount,"0"),copy:"Redacted installOAA.properties settings parsed from the shared settings path or management pod."},{label:"Certificates",value:formatValue(metrics.certificateCount||certificates.length,"0"),copy:"HTTPS endpoint certificates checked with openssl."},{label:"Properties",value:formatValue(metrics.propertyCount,"0"),copy:"Runtime property rows returned by the OAA API."}])}<div class="oaa-control-grid">${renderOaaMetricLoader()}${renderOaaProfilePanel(record,metrics,oaa,kubeHost)}${renderOaaDiagnostics(metrics)}</div><div class="content-stack">${metricBody}</div></div>`;
}
function renderGenericProductMetrics(productId,label,record){const products=resolvedProducts(record);const pathPanel=(productId==="soa")?`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">${escapeHtml(label)} Runtime Profile</h3><p class="panel-copy">Saved product paths are labeled with the product so shared connections stay clear.</p></div></div>${renderDefinitionList(productPathDefinitions(record,productId,label).concat([{key:"WebLogic Admin URL",value:((record.weblogic||{}).adminUrl)||"-"},{key:"SSH Host",value:(record.server||{}).host||"-"}]))}</section>`:"";return`<div class="content-stack">${renderSummaryTiles([{label:`${label} Enabled`,value:products[productId]?"Yes":"No",copy:`${label} is selected for this environment connection.`},{label:"Shared Connection",value:(record.server||{}).host||"-",copy:"Server SSH access saved for this environment."},{label:"WebLogic",value:productSelectionNeedsWeblogic(products)?"Enabled":"Not selected",copy:"Use the WebLogic tab for domain, deployment, thread, and JDBC details."},{label:"Environment Type",value:uppercaseType(record.environmentType),copy:"Primary product label for this environment."}])}${pathPanel}<section class="panel"><div class="panel-header"><div><h3 class="panel-title">${escapeHtml(label)} Metrics</h3><p class="panel-copy">This product is part of the saved connection.</p></div></div><p class="table-note">${escapeHtml(label)} registration is saved on this environment. Detailed product-specific runtime metrics will be expanded next; WebLogic details are available from the WebLogic tab when selected.</p></section></div>`;}
function numericMetric(v){const number=Number(v);return Number.isFinite(number)?number:0;}
function sumMetric(rows,key){return coerceList(rows).reduce(function(total,row){return total+numericMetric((row||{})[key]);},0);}
function maxMetric(rows,key){const values=coerceList(rows).map(function(row){return numericMetric((row||{})[key]);}).filter(function(value){return Number.isFinite(value);});return values.length?Math.max.apply(null,values):0;}
function renderRuntimeMetricTable(rows,columns,emptyTitle,emptyCopy){const items=coerceList(rows);if(items.length===0)return renderEmptyPanel(emptyTitle,emptyCopy);return`<div class="table-wrap"><table><thead><tr>${columns.map(function(column){return`<th>${escapeHtml(column.label)}</th>`;}).join("")}</tr></thead><tbody>${items.map(function(row){return`<tr>${columns.map(function(column){const raw=(row||{})[column.key];const value=column.format?column.format(raw,row):formatValue(raw,"-");return`<td>${escapeHtml(value)}</td>`;}).join("")}</tr>`;}).join("")}</tbody></table></div>`;}
function selectedWebLogicMetricGroups(){const selected=coerceList(state.loadedWeblogicMetricGroups).filter(function(id){return WEBLOGIC_RUNTIME_METRIC_GROUPS.some(function(group){return group.id===id;});});return selected.length?selected:[];}
function renderWebLogicMetricLoader(){const loaded=selectedWebLogicMetricGroups();return`<section class="panel weblogic-metric-loader"><div class="panel-header"><div><h3 class="panel-title">Load WebLogic Metrics</h3><p class="panel-copy">Select metric groups and load their latest collected WLST details.</p></div><div class="panel-actions"><button class="button is-primary" type="button" data-load-weblogic-metrics>Load</button></div></div><div class="metric-choice-grid">${renderMetricSelectAll("weblogicMetricGroup",loaded,WEBLOGIC_RUNTIME_METRIC_GROUPS)}${WEBLOGIC_RUNTIME_METRIC_GROUPS.map(function(group){const checked=loaded.includes(group.id)?"checked":"";return`<label class="checkbox-field metric-choice" for="weblogic-metric-${escapeHtml(group.id)}"><input id="weblogic-metric-${escapeHtml(group.id)}" name="weblogicMetricGroup" type="checkbox" value="${escapeHtml(group.id)}" ${checked}>${escapeHtml(group.label)}</label>`;}).join("")}</div></section>`;}
function renderWebLogicCriticalWidgets(metrics){const critical=(metrics||{}).criticalWidgets||{};return renderSummaryTiles([{label:"Heap Utilization",value:critical.heapUtilizationPercent==null?"-":formatPercent(critical.heapUtilizationPercent),copy:"Highest JVM heap utilization across server runtimes."},{label:"Pending Execute",value:formatValue(critical.pendingExecuteRequests,"0"),copy:"Pending user requests across thread pools."},{label:"Active JTA",value:formatValue(critical.activeJtaTransactions,"0"),copy:"Active transaction count across JTARuntime MBeans."},{label:"JMS Pending",value:formatValue(critical.jmsPendingMessages,"0"),copy:"Pending messages across JMS destinations."},{label:"JDBC Waiters",value:formatValue(critical.jdbcWaiters,"0"),copy:"Waiting JDBC connections across data sources."},{label:"Open Sockets",value:formatValue(critical.currentOpenSockets,"0"),copy:"Current open socket count across servers."},{label:"WorkManager Pending",value:formatValue(critical.workManagerPendingRequests,"0"),copy:"Pending requests across WorkManager runtimes."},{label:"JVM Uptime",value:formatValue(critical.jvmUptime,"-"),copy:"Longest JVM uptime reported by WLST."}]);}
function renderWebLogicSelectedMetricSections(metrics,deployments){const loaded=selectedWebLogicMetricGroups();const advanced=loaded.filter(function(id){return!WEBLOGIC_SECTION_METRIC_GROUPS.includes(id);});if(advanced.length===0)return"";const sections=[];if(advanced.includes("jta"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">JTA Metrics</h3><p class="panel-copy">Transaction health and transaction failure counters from JTARuntime.</p></div></div>${renderRuntimeMetricTable(metrics.jtaTransactions,[{key:"server",label:"Server"},{key:"activeTransactionsTotalCount",label:"Active"},{key:"transactionTotalCount",label:"Total"},{key:"committedTotalCount",label:"Committed"},{key:"rolledBackTotalCount",label:"Rolled Back"},{key:"heuristicsTotalCount",label:"Heuristics"},{key:"secondsActiveTotalCount",label:"Seconds Active"}],"No JTA metrics","No JTARuntime rows were returned by WLST.")}</section>`);if(advanced.includes("jms"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">JMS Queues</h3><p class="panel-copy">Queue depth, pending messages, consumers, and byte counts from JMSRuntime.</p></div></div>${renderRuntimeMetricTable(metrics.jmsDestinations,[{key:"server",label:"Server"},{key:"destination",label:"Destination"},{key:"messagesCurrentCount",label:"Current"},{key:"messagesPendingCount",label:"Pending"},{key:"messagesReceivedCount",label:"Received"},{key:"consumersCurrentCount",label:"Consumers"},{key:"bytesCurrentCount",label:"Bytes"}],"No JMS metrics","No JMS destination rows were returned by WLST.")}</section>`);if(advanced.includes("jvm"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">JVM Heap</h3><p class="panel-copy">Heap utilization and JVM identity from JVMRuntime.</p></div></div>${renderRuntimeMetricTable(metrics.jvmRuntime,[{key:"server",label:"Server"},{key:"heapFreeCurrent",label:"Heap Free"},{key:"heapSizeCurrent",label:"Heap Size"},{key:"heapFreePercent",label:"Free %"},{key:"javaVersion",label:"Java Version"},{key:"uptime",label:"Uptime"}],"No JVM metrics","No JVMRuntime rows were returned by WLST.")}</section>`);if(advanced.includes("threadPool"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Execute Queue</h3><p class="panel-copy">Thread pool saturation and pending request indicators.</p></div></div>${renderRuntimeMetricTable(metrics.threadPoolRuntime,[{key:"server",label:"Server"},{key:"executeThreadTotalCount",label:"Total Threads"},{key:"executeThreadIdleCount",label:"Idle Threads"},{key:"pendingUserRequestCount",label:"Pending Requests"},{key:"queueLength",label:"Queue Length"},{key:"hoggingThreadCount",label:"Hogging"},{key:"stuckThreadCount",label:"Stuck"},{key:"throughput",label:"Throughput"}],"No thread pool metrics","No ThreadPoolRuntime rows were returned by WLST.")}</section>`);if(advanced.includes("jdbcHealth"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">JDBC Health</h3><p class="panel-copy">Datasource failures, capacity, state, active connections, and waiters.</p></div></div>${renderRuntimeMetricTable(metrics.jdbcHealth,[{key:"server",label:"Server"},{key:"dataSource",label:"Data Source"},{key:"state",label:"State"},{key:"currCapacity",label:"Capacity"},{key:"activeConnectionsCurrentCount",label:"Active"},{key:"waitingForConnectionCurrentCount",label:"Waiting"},{key:"failuresToReconnectCount",label:"Reconnect Failures"},{key:"leakedConnectionCount",label:"Leaked"}],"No JDBC health metrics","No JDBC health rows were returned by WLST.")}</section>`);if(advanced.includes("sockets"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Socket Usage</h3><p class="panel-copy">Open, opened, and closed socket counters from SocketRuntime.</p></div></div>${renderRuntimeMetricTable(metrics.socketRuntime,[{key:"server",label:"Server"},{key:"currentOpenSocketCount",label:"Current Open"},{key:"socketsOpenedTotalCount",label:"Opened Total"},{key:"socketsClosedTotalCount",label:"Closed Total"}],"No socket metrics","No SocketRuntime rows were returned by WLST.")}</section>`);if(advanced.includes("workManagers"))sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">WorkManagers</h3><p class="panel-copy">Pending, completed, and stuck WorkManager request counts.</p></div></div>${renderRuntimeMetricTable(metrics.workManagers,[{key:"server",label:"Server"},{key:"workManager",label:"WorkManager"},{key:"pendingRequests",label:"Pending"},{key:"completedRequests",label:"Completed"},{key:"stuckThreadCount",label:"Stuck"}],"No WorkManager metrics","No WorkManager runtime rows were returned by WLST.")}</section>`);if(sections.length)sections.push(`<section class="panel metric-insight-panel"><div class="panel-header"><div><h3 class="panel-title">Critical Monitoring Widgets</h3><p class="panel-copy">Selected WebLogic runtime indicators from the latest WLST collection.</p></div></div>${renderWebLogicCriticalWidgets(metrics)}</section>`);if(metrics.runtimeMetricsError)sections.push(`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Runtime Metric Collection Error</h3><p class="panel-copy">WLST returned an error for the extended runtime pass.</p></div></div><p class="table-note">${escapeHtml(metrics.runtimeMetricsError)}</p></section>`);return sections.join("");}
function renderWebLogicJvmProcesses(metrics){return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">WebLogic Server Processes</h3><p class="panel-copy">JVM process metrics collected from each configured WebLogic cluster node host.</p></div></div>${renderRuntimeTable((metrics||{}).servers,"No WebLogic JVM processes were discovered on the configured node hosts.")}</section>`;}
function renderWebLogicServerCards(serverInventory){const rows=coerceList(serverInventory);if(rows.length===0)return"";return`<div class="server-card-grid">${rows.map(function(item){const state=String(item.state||"").toUpperCase();const tone=state==="RUNNING"?"healthy":(state==="SHUTDOWN"||state==="FAILED")?"down":"warning";const listen=`${formatValue(item.listenAddress,"-")}:${formatValue(item.port,"-")}`;return`<article class="server-metric-card"><div class="server-card-head"><div><p class="server-card-kicker">${escapeHtml(formatValue(item.type,"Server"))}</p><h4>${escapeHtml(formatValue(item.name,"-"))}</h4></div>${renderStatusPill(tone,formatValue(item.state,"Unknown"))}</div><div class="server-card-meta"><span><strong>Machine</strong>${escapeHtml(formatValue(item.machine,"-"))}</span><span><strong>Listen</strong>${escapeHtml(listen)}</span><span><strong>SSL</strong>${escapeHtml(formatValue(item.sslPort,"-"))}</span><span><strong>Cluster</strong>${escapeHtml(formatValue(item.cluster,"-"))}</span></div></article>`;}).join("")}</div>`;}
function renderWebLogicServerDetails(metrics,serverInventory){return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">WebLogic Domain Servers</h3><p class="panel-copy">Domain server inventory collected through WLST from ORACLE_HOME.</p></div></div>${serverInventory.length===0?renderEmptyPanel("No server inventory",metrics.serverInventoryError||"No WebLogic domain server inventory was returned for this environment."):`${renderWebLogicServerCards(serverInventory)}<div class="table-wrap metric-table-wrap"><table><thead><tr><th>Type</th><th>Server</th><th>State</th><th>Machine</th><th>Listen Address</th><th>IP</th><th>Port</th><th>SSL Port</th><th>Cluster</th></tr></thead><tbody>${serverInventory.map(function(item){return`<tr><td>${escapeHtml(formatValue(item.type,"-"))}</td><td>${escapeHtml(formatValue(item.name,"-"))}</td><td>${escapeHtml(formatValue(item.state,"-"))}</td><td>${escapeHtml(formatValue(item.machine,"-"))}</td><td>${escapeHtml(formatValue(item.listenAddress,"-"))}</td><td>${escapeHtml(formatValue(item.ip,"-"))}</td><td>${escapeHtml(formatValue(item.port,"-"))}</td><td>${escapeHtml(formatValue(item.sslPort,"-"))}</td><td>${escapeHtml(formatValue(item.cluster,"-"))}</td></tr>`;}).join("")}</tbody></table></div>`}${metrics.deploymentConnectUrl?`<p class="table-note">WLST connect URL: ${escapeHtml(metrics.deploymentConnectUrl)}</p>`:""}</section>`;}
function renderWebLogicSavedProfile(record,metrics,weblogic,adminHost){return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Saved WebLogic Profile</h3><p class="panel-copy">Saved WebLogic admin URL, credentials, paths, and server SSH access for this environment.</p></div></div>${renderDefinitionList([{key:"WebLogic Enabled",value:weblogic.enabled?"Yes":"No"},{key:"WebLogic Admin URL",value:weblogic.adminUrl||"-"},{key:"WebLogic Admin Username",value:weblogic.adminUsername||"-"},{key:"OUD Root User",value:((record.oud||{}).bindDn)||"cn=Directory Manager"},{key:"ORACLE_HOME Path",value:weblogic.oracleHome||"-"},{key:"WebLogic DOMAIN_HOME Path",value:weblogic.domainHome||"-"},{key:"WLST Path",value:metrics.deploymentCommand||"-"},{key:"OUD_INSTANCE_HOME Path",value:((record.oud||{}).instanceHome)||"-"},{key:"Server Host / IP",value:adminHost.host||"-"},{key:"Server SSH Port",value:formatValue(adminHost.port,"22")},{key:"Server SSH Username",value:adminHost.username||"-"},{key:"Server SSH Mode",value:sshModeLabel(resolveSshMode(adminHost))}])}</section>`;}
function renderWebLogicRuntimeStatus(metrics,stuckThreads,stuckThreadCount,hoggingThreadCount,serversWithStuckThreads,serversWithHoggingThreads){return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Runtime Status</h3><p class="panel-copy">Thread pool counts collected through WLST domain runtime.</p></div></div>${stuckThreads.length===0?renderEmptyPanel("No runtime status data",metrics.stuckThreadError||"No WebLogic runtime thread data was returned for this environment."):`${renderDefinitionList([{key:"Total Stuck Threads",value:formatValue(stuckThreadCount,"0")},{key:"Total Hogging Threads",value:formatValue(hoggingThreadCount,"0")},{key:"Servers With Stuck Threads",value:serversWithStuckThreads.join(", ")||"None"},{key:"Servers With Hogging Threads",value:serversWithHoggingThreads.join(", ")||"None"}])}<div class="table-wrap"><table><thead><tr><th>Server</th><th>Stuck Threads</th><th>Hogging Threads</th><th>Status</th></tr></thead><tbody>${stuckThreads.map(function(item){const stuckValue=item.stuckThreads==null?"-":String(item.stuckThreads);const hoggingValue=item.hoggingThreads==null?"-":String(item.hoggingThreads);const hasError=Boolean(item.error);const hasStuck=(item.stuckThreads||0)>0;const statusText=hasError?"Unavailable":hasStuck?"Stuck Threads Present":"OK";const pillState=hasError?"down":hasStuck?"warning":"healthy";return`<tr><td>${escapeHtml(formatValue(item.server,"-"))}</td><td>${escapeHtml(stuckValue)}</td><td>${escapeHtml(hoggingValue)}</td><td>${renderStatusPill(pillState,statusText)}</td></tr>`;}).join("")}</tbody></table></div>`}</section>`;}
function renderWebLogicConnectionPools(metrics,jdbcPools,jdbcPoolCount,jdbcActiveConnectionCount,jdbcWaitingConnectionCount,jdbcWaitingTone){return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">JDBC Connection Pools</h3><p class="panel-copy">Connection pool runtime counts collected through WLST domain runtime.</p></div></div>${jdbcPools.length===0?renderEmptyPanel("No JDBC pool data",metrics.jdbcPoolError||"No WebLogic JDBC connection pool data was returned for this environment."):`${renderDefinitionList([{key:"Connection Pools",value:formatValue(jdbcPoolCount,"0")},{key:"Active Connections",value:formatValue(jdbcActiveConnectionCount,"0")},{key:"Waiting Connections",value:formatValue(jdbcWaitingConnectionCount,"0"),tone:jdbcWaitingTone}])}<div class="table-wrap"><table><thead><tr><th>Server</th><th>Data Source</th><th>Active Connections</th><th>Waiting Connections</th></tr></thead><tbody>${jdbcPools.map(function(item){const waiting=parseInt(item.waitingConnections,10)||0;const waitingClass=waiting>0?' class="tone-warning"':"";return`<tr><td>${escapeHtml(formatValue(item.server,"-"))}</td><td>${escapeHtml(formatValue(item.dataSource,"-"))}</td><td>${escapeHtml(formatValue(item.activeConnections,"0"))}</td><td${waitingClass}>${escapeHtml(formatValue(item.waitingConnections,"0"))}</td></tr>`;}).join("")}</tbody></table></div>`}</section>`;}
function renderWebLogicApplicationDeployments(metrics,deployments){return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Application Deployment Status</h3><p class="panel-copy">Deployment states collected through WLST from ORACLE_HOME.</p></div></div>${deployments.length===0?renderEmptyPanel("No deployment data",metrics.deploymentError||"No WebLogic deployment states were returned for this environment."):`<div class="table-wrap"><table><thead><tr><th>Deployment</th><th>State</th></tr></thead><tbody>${deployments.map(function(item){const stateText=formatValue(item.state,"-");const pillState=stateText==="STATE_ACTIVE"?"healthy":"warning";const pillLabel=stateText==="STATE_ACTIVE"?"STATE_ACTIVE":stateText;return`<tr><td>${escapeHtml(formatValue(item.name,"-"))}</td><td>${renderStatusPill(pillState,pillLabel)}</td></tr>`;}).join("")}</tbody></table></div>`}</section>`;}
function renderWebLogicMetrics(record,dashboard){
const metrics=((dashboard.productMetrics||{}).weblogic)||{};
const weblogic=(record.weblogic||{});
const adminHost=weblogic.adminHost||{};
const deployments=coerceList(metrics.deployments);
const serverInventory=coerceList(metrics.serverInventory);
const stuckThreads=coerceList(metrics.stuckThreads);
const jdbcPools=coerceList(metrics.jdbcPools);
const configuredServerCount=serverInventory.length||coerceList(metrics.expectedServers).length||0;
const stuckThreadCount=parseInt(metrics.stuckThreadCount,10)||0;
const hoggingThreadCount=parseInt(metrics.hoggingThreadCount,10)||0;
const jdbcPoolCount=parseInt(metrics.jdbcPoolCount,10)||jdbcPools.length||0;
const jdbcActiveConnectionCount=parseInt(metrics.jdbcActiveConnectionCount,10)||0;
const jdbcWaitingConnectionCount=parseInt(metrics.jdbcWaitingConnectionCount,10)||0;
const serversWithStuckThreads=coerceList(metrics.serversWithStuckThreads);
const serversWithHoggingThreads=coerceList(metrics.serversWithHoggingThreads);
const jdbcWaitingTone=jdbcWaitingConnectionCount>0?"warning":"";
const loaded=selectedWebLogicMetricGroups();
const defaultSections=[loaded.includes("serverDetails")?renderWebLogicServerDetails(metrics,serverInventory):"",loaded.includes("serverDetails")?renderWebLogicSavedProfile(record,metrics,weblogic,adminHost):"",loaded.includes("runtimeStatus")?renderWebLogicRuntimeStatus(metrics,stuckThreads,stuckThreadCount,hoggingThreadCount,serversWithStuckThreads,serversWithHoggingThreads):"",loaded.includes("connectionPools")?renderWebLogicConnectionPools(metrics,jdbcPools,jdbcPoolCount,jdbcActiveConnectionCount,jdbcWaitingConnectionCount,jdbcWaitingTone):"",loaded.includes("appDeployments")?renderWebLogicApplicationDeployments(metrics,deployments):""].join("");
const metricSections=`${defaultSections}${renderWebLogicSelectedMetricSections(metrics,deployments)}`;
const metricBody=metricSections||renderEmptyPanel("No metric groups selected","Select one or more WebLogic metric groups and click Load.");
return`<div class="content-stack">${renderSummaryTiles([{label:"Configured Servers",value:formatValue(configuredServerCount,"0"),copy:"Domain servers returned by the WLST server inventory check."},{label:"Deployments",value:formatValue(metrics.deploymentCount,"0"),copy:"Applications returned by the WLST deployment-state check."},{label:"Active Deployments",value:formatValue(metrics.activeDeploymentCount,"0"),copy:"Deployments currently reporting STATE_ACTIVE."},{label:"Stuck Threads",value:formatValue(stuckThreadCount,"0"),copy:"Current stuck thread count returned by WLST thread pool runtime."},{label:"Hogging Threads",value:formatValue(hoggingThreadCount,"0"),copy:"Current hogging thread count returned by WLST thread pool runtime."}])}<div class="weblogic-metrics-layout"><aside class="weblogic-metric-sidebar">${renderWebLogicMetricLoader()}</aside><div class="weblogic-metric-results content-stack">${metricBody}</div></div></div>`;
return`<div class="content-stack">${renderSummaryTiles([{label:"Configured Servers",value:formatValue(configuredServerCount,"0"),copy:"Domain servers returned by the WLST server inventory check."},{label:"Deployments",value:formatValue(metrics.deploymentCount,"0"),copy:"Applications returned by the WLST deployment-state check."},{label:"Active Deployments",value:formatValue(metrics.activeDeploymentCount,"0"),copy:"Deployments currently reporting STATE_ACTIVE."},{label:"Stuck Threads",value:formatValue(stuckThreadCount,"0"),copy:"Current stuck thread count returned by WLST thread pool runtime."},{label:"Hogging Threads",value:formatValue(hoggingThreadCount,"0"),copy:"Current hogging thread count returned by WLST thread pool runtime."}])}${renderWebLogicMetricLoader()}${renderWebLogicSelectedMetricSections(metrics,deployments)}<section class="panel"><div class="panel-header"><div><h3 class="panel-title">WebLogic Domain Servers</h3><p class="panel-copy">Domain server inventory collected through WLST from ORACLE_HOME.</p></div></div>${serverInventory.length===0?renderEmptyPanel("No server inventory",metrics.serverInventoryError||"No WebLogic domain server inventory was returned for this environment."):`<div class="table-wrap"><table><thead><tr><th>Type</th><th>Server</th><th>State</th><th>Machine</th><th>Listen Address</th><th>IP</th><th>Port</th><th>SSL Port</th><th>Cluster</th></tr></thead><tbody>${serverInventory.map(function(item){return`<tr><td>${escapeHtml(formatValue(item.type,"-"))}</td><td>${escapeHtml(formatValue(item.name,"-"))}</td><td>${escapeHtml(formatValue(item.state,"-"))}</td><td>${escapeHtml(formatValue(item.machine,"-"))}</td><td>${escapeHtml(formatValue(item.listenAddress,"-"))}</td><td>${escapeHtml(formatValue(item.ip,"-"))}</td><td>${escapeHtml(formatValue(item.port,"-"))}</td><td>${escapeHtml(formatValue(item.sslPort,"-"))}</td><td>${escapeHtml(formatValue(item.cluster,"-"))}</td></tr>`;}).join("")}</tbody></table></div>`}${metrics.deploymentConnectUrl?`<p class="table-note">WLST connect URL: ${escapeHtml(metrics.deploymentConnectUrl)}</p>`:""}</section><div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Saved WebLogic Profile</h3><p class="panel-copy">Saved WebLogic admin URL, credentials, paths, and server SSH access for this environment.</p></div></div>${renderDefinitionList([{key:"With WebLogic",value:weblogic.enabled?"Yes":"No"},{key:"WebLogic Admin URL",value:weblogic.adminUrl||"-"},{key:"WebLogic Admin Username",value:weblogic.adminUsername||"-"},{key:"OUD Root User",value:((record.oud||{}).bindDn)||"cn=Directory Manager"},{key:"ORACLE_HOME Path",value:weblogic.oracleHome||"-"},{key:"WebLogic DOMAIN_HOME Path",value:weblogic.domainHome||"-"},{key:"WLST Path",value:metrics.deploymentCommand||"-"},{key:"OUD_INSTANCE_HOME Path",value:((record.oud||{}).instanceHome)||"-"},{key:"Server Host / IP",value:adminHost.host||"-"},{key:"Server SSH Port",value:formatValue(adminHost.port,"22")},{key:"Server SSH Username",value:adminHost.username||"-"},{key:"Server SSH Mode",value:sshModeLabel(resolveSshMode(adminHost))}])}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Stuck Threads</h3><p class="panel-copy">Thread pool counts collected through WLST domain runtime.</p></div></div>${stuckThreads.length===0?renderEmptyPanel("No stuck thread data",metrics.stuckThreadError||"No WebLogic stuck thread data was returned for this environment."):`${renderDefinitionList([{key:"Total Stuck Threads",value:formatValue(stuckThreadCount,"0")},{key:"Total Hogging Threads",value:formatValue(hoggingThreadCount,"0")},{key:"Servers With Stuck Threads",value:serversWithStuckThreads.join(", ")||"None"},{key:"Servers With Hogging Threads",value:serversWithHoggingThreads.join(", ")||"None"}])}<div class="table-wrap"><table><thead><tr><th>Server</th><th>Stuck Threads</th><th>Hogging Threads</th><th>Status</th></tr></thead><tbody>${stuckThreads.map(function(item){const stuckValue=item.stuckThreads==null?"-":String(item.stuckThreads);const hoggingValue=item.hoggingThreads==null?"-":String(item.hoggingThreads);const hasError=Boolean(item.error);const hasStuck=(item.stuckThreads||0)>0;const statusText=hasError?"Unavailable":hasStuck?"Stuck Threads Present":"OK";const pillState=hasError?"down":hasStuck?"warning":"healthy";return`<tr><td>${escapeHtml(formatValue(item.server,"-"))}</td><td>${escapeHtml(stuckValue)}</td><td>${escapeHtml(hoggingValue)}</td><td>${renderStatusPill(pillState,statusText)}</td></tr>`;}).join("")}</tbody></table></div>`}</section></div><section class="panel"><div class="panel-header"><div><h3 class="panel-title">JDBC Connection Pools</h3><p class="panel-copy">Connection pool runtime counts collected through WLST domain runtime.</p></div></div>${jdbcPools.length===0?renderEmptyPanel("No JDBC pool data",metrics.jdbcPoolError||"No WebLogic JDBC connection pool data was returned for this environment."):`${renderDefinitionList([{key:"Connection Pools",value:formatValue(jdbcPoolCount,"0")},{key:"Active Connections",value:formatValue(jdbcActiveConnectionCount,"0")},{key:"Waiting Connections",value:formatValue(jdbcWaitingConnectionCount,"0"),tone:jdbcWaitingTone}])}<div class="table-wrap"><table><thead><tr><th>Server</th><th>Data Source</th><th>Active Connections</th><th>Waiting Connections</th></tr></thead><tbody>${jdbcPools.map(function(item){const waiting=parseInt(item.waitingConnections,10)||0;const waitingClass=waiting>0?' class="tone-warning"':"";return`<tr><td>${escapeHtml(formatValue(item.server,"-"))}</td><td>${escapeHtml(formatValue(item.dataSource,"-"))}</td><td>${escapeHtml(formatValue(item.activeConnections,"0"))}</td><td${waitingClass}>${escapeHtml(formatValue(item.waitingConnections,"0"))}</td></tr>`;}).join("")}</tbody></table></div>`}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Application Deployment Status</h3><p class="panel-copy">Deployment states collected through WLST from ORACLE_HOME.</p></div></div>${deployments.length===0?renderEmptyPanel("No deployment data",metrics.deploymentError||"No WebLogic deployment states were returned for this environment."):`<div class="table-wrap"><table><thead><tr><th>Deployment</th><th>State</th></tr></thead><tbody>${deployments.map(function(item){const stateText=formatValue(item.state,"-");const pillState=stateText==="STATE_ACTIVE"?"healthy":"warning";const pillLabel=stateText==="STATE_ACTIVE"?"STATE_ACTIVE":stateText;return`<tr><td>${escapeHtml(formatValue(item.name,"-"))}</td><td>${renderStatusPill(pillState,pillLabel)}</td></tr>`;}).join("")}</tbody></table></div>`}</section></div>`;}
function renderWebLogicProductTabs(activeTab){return`<section class="panel weblogic-product-tabs"><div class="tab-row"><button class="tab-button ${activeTab==="oracleHome"?"is-active":""}" type="button" data-weblogic-product-tab="oracleHome">ORACLE_HOME</button><button class="tab-button ${activeTab==="weblogic"?"is-active":""}" type="button" data-weblogic-product-tab="weblogic">WebLogic Server</button></div></section>`;}
function renderWebLogicOracleHomeTab(record,metrics,weblogic,adminHost){const nodes=weblogicOracleHomeNodes(metrics,weblogic,adminHost);const activeId=nodes.some(function(node){return node.id===state.activeWeblogicOracleHomeNode;})?state.activeWeblogicOracleHomeNode:(nodes[0]||{}).id||"node1";const activeNode=nodes.find(function(node){return node.id===activeId;})||nodes[0]||{};const sshProfile=Object.assign({},adminHost,{port:activeNode.port||adminHost.port,username:activeNode.username||adminHost.username,sshMode:activeNode.sshMode||adminHost.sshMode});return`<div class="content-stack">${renderWebLogicOracleHomeNodeSelector(nodes,activeId)}<div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">ORACLE_HOME Profile</h3><p class="panel-copy">Saved middleware paths and WLST entry point used for the selected WebLogic node.</p></div></div>${renderDefinitionList([{key:"Selected Node",value:activeNode.name||"Node 1"},{key:"Node Host / IP",value:activeNode.host||adminHost.host||"-"},{key:"ORACLE_HOME Path",value:activeNode.oracleHome||weblogic.oracleHome||"-"},{key:"WebLogic DOMAIN_HOME Path",value:activeNode.domainHome||weblogic.domainHome||"-"},{key:"WLST Path",value:metrics.deploymentCommand||metrics.serverInventoryCommand||"-"},{key:"WebLogic Admin Server URL",value:weblogic.adminUrl||"-"},{key:"WebLogic Admin Username",value:weblogic.adminUsername||"-"}])}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Collection Host</h3><p class="panel-copy">Server SSH profile used to run WLST, OPatch, and certificate checks from the selected node ORACLE_HOME.</p></div></div>${renderDefinitionList([{key:"Node Role",value:activeNode.role||"AdminServer host"},{key:"Server Host / IP",value:activeNode.host||adminHost.host||"-"},{key:"Server SSH Port",value:formatValue(sshProfile.port,"22")},{key:"Server SSH Username",value:sshProfile.username||"-"},{key:"Server SSH Mode",value:sshModeLabel(resolveSshMode(sshProfile))}])}</section></div>${renderWebLogicOpatchInventory(activeNode.opatch||metrics.opatch||{})}${renderWebLogicCertificates(activeNode.certificates||metrics.certificates,activeNode.certificateError||metrics.certificateError)}</div>`;}
function renderWebLogicMetrics(record,dashboard){const metrics=((dashboard.productMetrics||{}).weblogic)||{};const weblogic=(record.weblogic||{});const adminHost=weblogic.adminHost||{};const deployments=coerceList(metrics.deployments);const serverInventory=coerceList(metrics.serverInventory);const stuckThreads=coerceList(metrics.stuckThreads);const jdbcPools=coerceList(metrics.jdbcPools);const configuredServerCount=serverInventory.length||0;const stuckThreadCount=parseInt(metrics.stuckThreadCount,10)||0;const hoggingThreadCount=parseInt(metrics.hoggingThreadCount,10)||0;const jdbcPoolCount=parseInt(metrics.jdbcPoolCount,10)||jdbcPools.length||0;const jdbcActiveConnectionCount=parseInt(metrics.jdbcActiveConnectionCount,10)||0;const jdbcWaitingConnectionCount=parseInt(metrics.jdbcWaitingConnectionCount,10)||0;const serversWithStuckThreads=coerceList(metrics.serversWithStuckThreads);const serversWithHoggingThreads=coerceList(metrics.serversWithHoggingThreads);const jdbcWaitingTone=jdbcWaitingConnectionCount>0?"warning":"";const loaded=selectedWebLogicMetricGroups();const activeTab=state.activeWeblogicProductTab==="oracleHome"?"oracleHome":"weblogic";const defaultSections=[loaded.includes("serverDetails")?renderWebLogicServerDetails(metrics,serverInventory):"",loaded.includes("serverDetails")?renderWebLogicJvmProcesses(metrics):"",loaded.includes("runtimeStatus")?renderWebLogicRuntimeStatus(metrics,stuckThreads,stuckThreadCount,hoggingThreadCount,serversWithStuckThreads,serversWithHoggingThreads):"",loaded.includes("connectionPools")?renderWebLogicConnectionPools(metrics,jdbcPools,jdbcPoolCount,jdbcActiveConnectionCount,jdbcWaitingConnectionCount,jdbcWaitingTone):"",loaded.includes("appDeployments")?renderWebLogicApplicationDeployments(metrics,deployments):""].join("");const metricSections=`${defaultSections}${renderWebLogicSelectedMetricSections(metrics,deployments)}`;const metricBody=metricSections||renderEmptyPanel("No metric groups selected","Select one or more WebLogic metric groups and click Load.");const tabContent=activeTab==="oracleHome"?renderWebLogicOracleHomeTab(record,metrics,weblogic,adminHost):`<div class="weblogic-metrics-layout"><aside class="weblogic-metric-sidebar">${renderWebLogicMetricLoader()}</aside><div class="weblogic-metric-results content-stack">${metricBody}</div></div>`;return`<div class="content-stack">${renderSummaryTiles([{label:"WebLogic Servers",value:formatValue(configuredServerCount,"0"),copy:"Domain servers discovered dynamically through WLST."},{label:"Deployments",value:formatValue(metrics.deploymentCount,"0"),copy:"Applications returned by the WLST deployment-state check."},{label:"Active Deployments",value:formatValue(metrics.activeDeploymentCount,"0"),copy:"Deployments currently reporting STATE_ACTIVE."},{label:"Stuck Threads",value:formatValue(stuckThreadCount,"0"),copy:"Current stuck thread count returned by WLST thread pool runtime."},{label:"Hogging Threads",value:formatValue(hoggingThreadCount,"0"),copy:"Current hogging thread count returned by WLST thread pool runtime."}])}${renderWebLogicProductTabs(activeTab)}${tabContent}</div>`;}
function selectedOidMetricGroups(){const selected=coerceList(state.loadedOidMetricGroups).filter(function(id){return OID_METRIC_GROUPS.some(function(group){return group.id===id;});});return selected.length?selected:[];}
function renderOidMetricLoader(){const loaded=selectedOidMetricGroups();return`<section class="panel oid-metric-loader"><div class="panel-header"><div><h3 class="panel-title">Load OID Metrics</h3><p class="panel-copy">Select OID LDAP, monitoring, patch, and certificate groups from the latest collection.</p></div><div class="panel-actions"><button class="button is-primary" type="button" data-load-oid-metrics>Load</button></div></div><div class="metric-choice-grid">${renderMetricSelectAll("oidMetricGroup",loaded,OID_METRIC_GROUPS)}${OID_METRIC_GROUPS.map(function(group){const checked=loaded.includes(group.id)?"checked":"";return`<label class="checkbox-field metric-choice" for="oid-metric-${escapeHtml(group.id)}"><input id="oid-metric-${escapeHtml(group.id)}" name="oidMetricGroup" type="checkbox" value="${escapeHtml(group.id)}" ${checked}>${escapeHtml(group.label)}</label>`;}).join("")}</div></section>`;}
function renderOidProductTabs(activeTab,hasWeblogic){return`<section class="panel weblogic-product-tabs"><div class="tab-row"><button class="tab-button ${activeTab==="oracleHome"?"is-active":""}" type="button" data-oid-product-tab="oracleHome">ORACLE_HOME</button>${hasWeblogic?`<button class="tab-button ${activeTab==="weblogic"?"is-active":""}" type="button" data-oid-product-tab="weblogic">WebLogic Server</button>`:""}</div></section>`;}
function oidTruthyValue(value){return["1","true","yes","enabled"].includes(String(value||"").trim().toLowerCase());}
function oidStatusAttributeName(group){if(group.id==="externalPlugins")return"orclpluginenable";if(group.id==="passwordPolicies")return"orclpwdpolicyenable";return"";}
function oidGroupedRows(rows){const groups=[];const byEntry={};coerceList(rows).forEach(function(row){const entry=String(row.entry||row.dn||"-");if(!byEntry[entry]){byEntry[entry]={entry:entry,rows:[]};groups.push(byEntry[entry]);}byEntry[entry].rows.push(row);});return groups;}
function oidEntryStatus(group,rows){const statusAttr=oidStatusAttributeName(group);if(!statusAttr)return null;const statusRow=coerceList(rows).find(function(row){return String(row.name||row.attribute||"").trim().toLowerCase()===statusAttr;});if(!statusRow)return null;const enabled=oidTruthyValue(statusRow.value);return{enabled:enabled,label:enabled?"Enabled":"Disabled",state:enabled?"healthy":"warning"};}
function renderOidLdapValue(group,row){const name=String(row.name||row.attribute||"").trim().toLowerCase();const value=String(row.value||"").trim();if(name&&name===oidStatusAttributeName(group)){const enabled=oidTruthyValue(value);return renderStatusPill(enabled?"healthy":"warning",enabled?"Enabled":"Disabled");}return escapeHtml(formatValue(row.value,"-"));}
function renderOidGroupedEntryPanel(group,entryGroup){const status=oidEntryStatus(group,entryGroup.rows);const entryClass=status&&status.enabled?" oid-entry-card is-enabled":" oid-entry-card";return`<section class="${entryClass}"><div class="oid-entry-header"><h4 class="oid-entry-title">${escapeHtml(entryGroup.entry)}</h4>${status?renderStatusPill(status.state,status.label):""}</div><div class="table-wrap"><table><thead><tr><th>Attribute</th><th>Value</th></tr></thead><tbody>${entryGroup.rows.map(function(row){const attr=String(row.name||row.attribute||"-");const isStatus=String(attr).trim().toLowerCase()===oidStatusAttributeName(group);const rowClass=isStatus?` class="is-status-field ${status&&status.enabled?"is-enabled":"is-disabled"}"`:"";return`<tr${rowClass}><td>${escapeHtml(attr)}</td><td>${renderOidLdapValue(group,row)}</td></tr>`;}).join("")}</tbody></table></div></section>`;}
function renderOidGroupedLdapPanel(metrics,group,rows,data,error,command){const grouped=oidGroupedRows(rows);return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">${escapeHtml(group.label)}</h3><p class="panel-copy">${escapeHtml(data.baseDn?`LDAP search base ${data.baseDn}.`:"OID LDAP and monitoring information from the latest collector run.")}</p></div></div>${grouped.length===0?renderEmptyPanel(`No ${group.label} rows`,error||"No OID LDAP rows were returned for this metric group."):`<div class="oid-entry-stack">${grouped.map(function(entryGroup){return renderOidGroupedEntryPanel(group,entryGroup);}).join("")}</div>${error?`<p class="table-note">${escapeHtml(error)}</p>`:""}`}${command?`<p class="table-note">Command: ${escapeHtml(command)}</p>`:""}</section>`;}
function renderOidLdapGroupPanel(metrics,group){const data=((metrics||{}).ldapGroups||{})[group.id]||{};const rows=coerceList(data.rows).filter(function(row){return group.id!=="configset"||String(row.name||row.attribute||"").trim().toLowerCase()!=="orclaci";});const command=data.command||"";const error=data.error||"";if(group.id==="externalPlugins"||group.id==="passwordPolicies")return renderOidGroupedLdapPanel(metrics,group,rows,data,error,command);return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">${escapeHtml(group.label)}</h3><p class="panel-copy">${escapeHtml(data.baseDn?`LDAP search base ${data.baseDn}.`:"OID LDAP and monitoring information from the latest collector run.")}</p></div></div>${rows.length===0?renderEmptyPanel(`No ${group.label} rows`,error||"No OID LDAP rows were returned for this metric group."):`<div class="table-wrap"><table><thead><tr><th>Entry</th><th>Attribute</th><th>Value</th></tr></thead><tbody>${rows.map(function(row){return`<tr><td>${escapeHtml(row.entry||row.dn||"-")}</td><td>${escapeHtml(row.name||row.attribute||"-")}</td><td>${renderOidLdapValue(group,row)}</td></tr>`;}).join("")}</tbody></table></div>${error?`<p class="table-note">${escapeHtml(error)}</p>`:""}`}${command?`<p class="table-note">Command: ${escapeHtml(command)}</p>`:""}</section>`;}
function renderOidInstancesPanel(metrics){const rows=coerceList((metrics||{}).instances);return`<section class="panel oid-instance-summary"><div class="panel-header"><div><h3 class="panel-title">OID Instances</h3><p class="panel-copy">Instance-level configset summary grouped from cn=osdldapd,cn=subconfigsubentry. ACI attributes are kept in the orclaci section.</p></div></div>${rows.length===0?renderEmptyPanel("No OID instances","No OID instance configset entries were discovered."):`<div class="table-wrap"><table><thead><tr><th>Instance</th><th>LDAP Port</th><th>LDAPS Port</th><th>Host</th><th>Mode</th><th>SSL</th><th>Processes</th><th>Dispatch Threads</th><th>Max Connections</th></tr></thead><tbody>${rows.map(function(row){return`<tr><td>${escapeHtml(formatValue(row.name,"OID Instance"))}</td><td>${escapeHtml(formatValue(row.ldapPort,"-"))}</td><td>${escapeHtml(formatValue(row.ldapsPort,"-"))}</td><td>${escapeHtml(formatValue(row.host,"-"))}</td><td>${escapeHtml(formatValue(row.serverMode,"-"))}</td><td>${escapeHtml(formatValue(row.sslEnabled,"-"))}</td><td>${escapeHtml(formatValue(row.serverProcesses,"-"))}</td><td>${escapeHtml(formatValue(row.dispatcherThreads,"-"))}</td><td>${escapeHtml(formatValue(row.maxConnections,"-"))}</td></tr>`;}).join("")}</tbody></table></div><div class="compact-kv-grid oid-instance-counts"><div class="compact-kv-item"><span class="compact-kv-key">Instances</span><span class="compact-kv-value">${escapeHtml(formatValue(rows.length,"0"))}</span></div><div class="compact-kv-item"><span class="compact-kv-key">LDAP Ports</span><span class="compact-kv-value">${escapeHtml(coerceList((metrics||{}).ldapPorts).join(", ")||"-")}</span></div><div class="compact-kv-item"><span class="compact-kv-key">LDAPS Ports</span><span class="compact-kv-value">${escapeHtml(coerceList((metrics||{}).ldapsPorts).join(", ")||"-")}</span></div></div>`}</section>`;}
function renderOidCertificates(certificates,error){const rows=coerceList(certificates);return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">OID Certificates</h3><p class="panel-copy">Certificate names and expiry dates collected from every discovered OID LDAPS listener port.</p></div></div>${rows.length===0?renderEmptyPanel("No OID certificates",error||"No OID SSL listener certificate details were returned."):`<div class="table-wrap"><table><thead><tr><th>Instance</th><th>Endpoint</th><th>Subject</th><th>Issuer</th><th>Expires</th><th>Status</th></tr></thead><tbody>${rows.map(function(item){const status=String(item.status||"healthy");const pillState=status==="expired"?"down":status==="warning"?"warning":"healthy";const endpoint=`${formatValue(item.host,"-")}:${formatValue(item.port,"-")}`;return`<tr><td>${escapeHtml(item.instanceName||item.server||"-")}</td><td>${escapeHtml(endpoint)}</td><td>${escapeHtml(item.subject||"-")}</td><td>${escapeHtml(item.issuer||"-")}</td><td>${escapeHtml(item.expiresAt||"-")}</td><td>${renderStatusPill(pillState,item.statusLabel||startCase(status))}</td></tr>`;}).join("")}</tbody></table></div>${error?`<p class="table-note">${escapeHtml(error)}</p>`:""}`}</section>`;}
function renderOidProcessPanel(metrics){const rows=coerceList((metrics||{}).processes);return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">OID Processes And Ports</h3><p class="panel-copy">Ports discovered from ps -ef output for oidldapd processes.</p></div></div>${rows.length===0?renderEmptyPanel("No oidldapd processes",(metrics||{}).processError||"No oidldapd process rows were returned by ps -ef."):`<div class="table-wrap"><table><thead><tr><th>Instance</th><th>PID</th><th>Host</th><th>LDAP Port</th><th>LDAPS Port</th><th>Command</th></tr></thead><tbody>${rows.map(function(row){return`<tr><td>${escapeHtml(formatValue(row.instanceName,"-"))}</td><td>${escapeHtml(formatValue(row.pid,"-"))}</td><td>${escapeHtml(formatValue(row.host,"-"))}</td><td>${escapeHtml(formatValue(row.ldapPort,"-"))}</td><td>${escapeHtml(formatValue(row.ldapsPort,"-"))}</td><td>${escapeHtml(formatValue(row.command,"-"))}</td></tr>`;}).join("")}</tbody></table></div>`}${(metrics||{}).processCommand?`<p class="table-note">Command: ${escapeHtml(metrics.processCommand)}</p>`:""}</section>`;}
function renderOidProfilePanel(record,metrics){const oid=(record||{}).oid||{};const server=(record||{}).server||{};return`<div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">OID Profile</h3><p class="panel-copy">Saved OID administrator and ORACLE_HOME settings for this connection.</p></div></div>${renderDefinitionList([{key:"OID Host",value:oid.host||server.host||"-"},{key:"OID ORACLE_HOME",value:oid.oracleHome||"-"},{key:"OID Administrator",value:oid.adminUsername||"cn=orcladmin"},{key:"Discovered LDAP Port",value:formatValue((metrics||{}).ldapPort,"-")},{key:"Discovered LDAPS Port",value:formatValue((metrics||{}).ldapsPort,"-")},{key:"WebLogic Details",value:oid.weblogicEnabled?"Enabled":"Not selected"}])}</section><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Collection Host</h3><p class="panel-copy">Server SSH profile used for oidldapd, ldapsearch, OPatch, and certificate checks.</p></div></div>${renderDefinitionList([{key:"Server Host / IP",value:server.host||oid.host||"-"},{key:"Server SSH Port",value:formatValue(server.port,"22")},{key:"Server SSH Username",value:server.username||"-"},{key:"Server SSH Mode",value:sshModeLabel(resolveSshMode(server))}])}</section></div>`;}
