async function checkForUpdates(){if(state.isCheckingUpdates)return;syncUpdateCheckVersion();state.isCheckingUpdates=true;state.updateCheck=Object.assign({},state.updateCheck||{currentVersion:currentVersion()},{status:"checking",message:"Checking GitHub for updates..."});renderUpdateCheckStatus();try{const result=await fetchJson("/api/admin/updates/check");state.updateCheck=result;if(result.status==="update_available")setMessage(`Update available on GitHub: ${result.remoteVersion}.`,"info");else if(result.status==="current")setMessage(`This dashboard is up to date on ${result.currentVersion}.`,"success");else if(result.status==="ahead")setMessage(`This dashboard is ahead of GitHub ${result.branch||"main"} on ${result.currentVersion}.`,"info");else if(result.status==="different")setMessage(result.message||"GitHub reports a different version for this dashboard.","info");else if(result.status==="error")setMessage(result.message||"GitHub update check failed.","error");}catch(error){state.updateCheck={status:"error",currentVersion:currentVersion(),remoteVersion:"",message:error.message,checkedAt:""};setMessage(error.message,"error");}finally{state.isCheckingUpdates=false;renderUpdateCheckStatus();}}
