async function loadLogScopeFiles(profileId,groupId){const envId=currentEnvironmentId();const logState=currentLogScopeState();state.logScope=Object.assign({},logState,{activeProfileId:profileId,activeGroupId:groupId,files:[],selectedFile:"",logText:"",isLoading:true,isReading:false,error:"",fileFilter:""});render();try{const result=await fetchJson(`/api/environments/${encodeURIComponent(envId)}/logs/list`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({profileId:profileId,groupId:groupId})});state.logScope=Object.assign({},state.logScope,{files:coerceList(result.files),isLoading:false,error:""});render();}catch(error){state.logScope=Object.assign({},state.logScope,{files:[],isLoading:false,error:error.message});setMessage(error.message,"error");render();}}
