const LOGSCOPE_LEVEL_ORDER=["ERROR","WARNING","NOTIFICATION","INFO","DEBUG","OTHER"];
function defaultLogScopeState(envId){return{environmentId:envId||"",profiles:[],activeProfileId:"",activeGroupId:"",files:[],selectedFile:"",logText:"",isLoading:false,isReading:false,error:"",viewMode:"tail",tailLines:500,latestFirst:false,logReadMode:"",fullAnalysisOpen:false,analysisMaximized:false,filterText:"",filterLevel:"all",filterLogger:"",analysisOnlyProblems:false,fileFilter:"",selectedLogLevels:LOGSCOPE_LEVEL_ORDER.slice(),selectedLoggers:null};}
function logScopeLevelCounts(entries){return entries.reduce(function(counts,entry){counts[entry.level]=(counts[entry.level]||0)+1;return counts;},{});}
function logScopeLoggerCounts(entries){const counts={};entries.forEach(function(entry){const logger=entry.logger||"Unparsed logger";counts[logger]=(counts[logger]||0)+1;});return Object.keys(counts).map(function(name){return{name:name,count:counts[name]};}).sort(function(a,b){return b.count-a.count||a.name.localeCompare(b.name);});}
function logScopeSelectedLevels(logState,counts){const available=LOGSCOPE_LEVEL_ORDER.filter(function(level){return (counts[level]||0)>0;});if(!available.length)return LOGSCOPE_LEVEL_ORDER.slice();const selected=Array.isArray(logState.selectedLogLevels)?logState.selectedLogLevels:available;return selected.filter(function(level){return available.includes(level);});}
function logScopeSelectedLoggers(logState,loggerRows){const names=loggerRows.map(function(row){return row.name;});if(!names.length)return[];if(!Array.isArray(logState.selectedLoggers))return names;return logState.selectedLoggers.filter(function(name){return names.includes(name);});}
function logScopeFilteredEntries(logState){const entries=logScopeEntries(logState);const counts=logScopeLevelCounts(entries);const loggerRows=logScopeLoggerCounts(entries);const selectedLevels=logScopeSelectedLevels(logState,counts);const selectedLoggers=logScopeSelectedLoggers(logState,loggerRows);const text=String(logState.filterText||"").trim().toLowerCase();const loggerContains=String(logState.filterLogger||"").trim().toLowerCase();return entries.filter(function(entry){const logger=entry.logger||"Unparsed logger";if(logState.analysisOnlyProblems&&!entry.problem)return false;if(selectedLevels.length&&!selectedLevels.includes(entry.level))return false;if(selectedLoggers.length&&!selectedLoggers.includes(logger))return false;if(loggerContains&&logger.toLowerCase().indexOf(loggerContains)===-1)return false;if(text&&entry.line.toLowerCase().indexOf(text)===-1)return false;return true;});}
function logScopeProblemRows(entries){const patterns=[{label:"Exception / stack",pattern:/\b(exception|stacktrace|caused by)\b/i},{label:"Failure",pattern:/\b(failed|failure|unable|cannot|could not)\b/i},{label:"Timeout",pattern:/\b(timeout|timed out|stuck)\b/i},{label:"Denied / auth",pattern:/\b(denied|unauthorized|authentication|authorization)\b/i},{label:"ORA / BEA / IAM",pattern:/\b(ORA|BEA|IAM)-\d+\b/i}];return patterns.map(function(item){const count=entries.filter(function(entry){return item.pattern.test(entry.line);}).length;return{label:item.label,count:count};}).filter(function(item){return item.count>0;});}
function renderLogScopeRefinePanel(logState,entries,counts,loggerRows){const selectedLevels=logScopeSelectedLevels(logState,counts);const selectedLoggers=logScopeSelectedLoggers(logState,loggerRows);const allLevelsSelected=LOGSCOPE_LEVEL_ORDER.filter(function(level){return(counts[level]||0)>0;}).every(function(level){return selectedLevels.includes(level);});const allLoggersSelected=loggerRows.length>0&&loggerRows.every(function(row){return selectedLoggers.includes(row.name);});return`<aside class="logscope-refine-panel"><div class="refine-block"><div class="refine-heading"><span>Levels</span><button class="link-button" type="button" data-logscope-level-select-all="${allLevelsSelected?"none":"all"}">${allLevelsSelected?"Clear":"All"}</button></div>${LOGSCOPE_LEVEL_ORDER.map(function(level){const count=counts[level]||0;if(!count)return"";const checked=selectedLevels.includes(level)?"checked":"";return`<label class="refine-check"><input type="checkbox" name="logscopeLevelFilter" value="${escapeHtml(level)}" ${checked}><span class="logscope-level logscope-level-${level.toLowerCase()}">${escapeHtml(level)}</span><strong>${escapeHtml(count)}</strong></label>`;}).join("")}</div><div class="refine-block"><div class="refine-heading"><span>Problem Strings</span><span>${escapeHtml(entries.filter(function(entry){return entry.problem;}).length)}</span></div>${logScopeProblemRows(entries).map(function(row){return`<button class="refine-chip" type="button" data-logscope-quick-search="${escapeHtml(row.label.split(" ")[0])}"><span>${escapeHtml(row.label)}</span><strong>${escapeHtml(row.count)}</strong></button>`;}).join("")||'<p class="table-note">No common problem strings detected.</p>'}</div><div class="refine-block refine-loggers"><div class="refine-heading"><span>Loggers</span><button class="link-button" type="button" data-logscope-logger-select-all="${allLoggersSelected?"none":"all"}">${allLoggersSelected?"Clear":"All"}</button></div>${loggerRows.map(function(row){const checked=selectedLoggers.includes(row.name)?"checked":"";return`<label class="refine-check refine-logger-check"><input type="checkbox" name="logscopeLoggerFilter" value="${escapeHtml(row.name)}" ${checked}><span>${escapeHtml(row.name)}</span><strong>${escapeHtml(row.count)}</strong></label>`;}).join("")||'<p class="table-note">No Java logger names parsed.</p>'}</div></aside>`;}
function renderLogScopeAnalysis(logState){const entries=logScopeEntries(logState);if(!entries.length)return renderEmptyPanel("No log entries loaded","Open a complete log file first, then run Detailed Log Analysis.");const counts=logScopeLevelCounts(entries);const loggerRows=logScopeLoggerCounts(entries);const filtered=logScopeFilteredEntries(logState);const cards=renderSummaryTiles([{label:"Entries",value:entries.length,copy:"Lines parsed from the complete log."},{label:"Problem Indicators",value:entries.filter(function(entry){return entry.problem;}).length,copy:"Errors, warnings, exceptions, failures, stuck, denied, and timeout text.",tone:"warning"},{label:"Errors",value:counts.ERROR||0,copy:"ERROR, SEVERE, CRITICAL, FATAL, ORA, BEA, and IAM codes.",tone:(counts.ERROR||0)>0?"critical":"healthy"},{label:"Warnings",value:counts.WARNING||0,copy:"WARNING and WARN entries.",tone:(counts.WARNING||0)>0?"warning":"healthy"},{label:"Loggers",value:loggerRows.length,copy:"Distinct Java logger names detected."}]);return`<div class="logscope-workspace">${renderLogScopeRefinePanel(logState,entries,counts,loggerRows)}<section class="logscope-analysis-main">${cards}<div class="logscope-search-grid"><div class="field"><label>Search All Parsed Text</label><input class="input-field" type="search" data-logscope-filter-text placeholder="ECID, logger, message, host, user, error..." value="${escapeHtml(logState.filterText||"")}"></div><div class="field"><label>Logger Contains</label><input class="input-field" type="search" data-logscope-logger-filter placeholder="oracle.iam, weblogic, ODL..." value="${escapeHtml(logState.filterLogger||"")}"></div><label class="checkbox-row logscope-problem-toggle"><input type="checkbox" data-logscope-problems-only ${logState.analysisOnlyProblems?"checked":""}> Show problems only</label><button class="button" type="button" data-logscope-clear-filters>Clear Filters</button></div><div class="logscope-analysis-count">${filtered.length} matching entries across the loaded ${escapeHtml(logState.logReadMode==="tail"?"tail":"complete log")}.</div>${!filtered.length?renderEmptyPanel("No matching log entries","Adjust the search text, loggers, or levels to broaden the detailed analysis."):`<div class="logscope-analysis-list">${filtered.slice(0,2000).map(function(entry){return`<article class="logscope-entry ${entry.problem?"is-problem":""}"><div class="logscope-entry-head"><span class="logscope-level logscope-level-${entry.level.toLowerCase()}">${escapeHtml(entry.level)}</span>${entry.timestamp?`<strong>${escapeHtml(entry.timestamp)}</strong>`:""}${entry.code?`<span>${escapeHtml(entry.code)}</span>`:""}${entry.logger?`<span class="logscope-entry-logger">${escapeHtml(entry.logger)}</span>`:""}<span>line ${entry.index}</span></div><pre>${escapeHtml(entry.line)}</pre></article>`;}).join("")}</div>${filtered.length>2000?`<p class="table-note">Showing the first 2000 matching entries. Narrow the filters to inspect a smaller set.</p>`:""}`}</section></div>`;}
function renderLogScopeAnalysisModal(logState){if(!logState.fullAnalysisOpen)return"";const selected=findLogScopeSelection(logState.profiles,logState.activeProfileId,logState.activeGroupId);const maximized=Boolean(logState.analysisMaximized);return`<div class="logscope-analysis-modal-backdrop ${maximized?"is-maximized":""}" role="dialog" aria-modal="true"><section class="logscope-analysis-modal ${maximized?"is-maximized":""}"><header class="logscope-analysis-modal-header"><div><p class="eyebrow">LogScope Diagnostic Workspace</p><h2>Detailed Log Analysis</h2><p>${escapeHtml(logState.selectedFile||"No file selected")} ${selected.group?`from ${escapeHtml(selected.group.name)}`:""}</p></div><div class="panel-actions"><label class="checkbox-row"><input type="checkbox" data-logscope-latest-first ${logState.latestFirst?"checked":""}> Newest first</label><button class="button" type="button" data-logscope-load-complete ${logState.selectedFile?"":"disabled"}>Reload Complete</button><button class="button" type="button" data-logscope-analysis-maximize>${maximized?"Restore":"Maximize"}</button><button class="button" type="button" data-logscope-analysis-close>Close</button></div></header><main class="logscope-analysis-modal-body">${logState.isReading?renderLogScopeTerminal("Loading complete log file...","Loading complete log file...",true,"complete"):renderLogScopeAnalysis(logState)}</main></section></div>`;}
