function nodeVisualStatusTone(row){const rawStatus=String(((row||{}).health||{}).status||((row||{}).reachable?"healthy":"down")).toLowerCase();return rawStatus==="critical"||rawStatus==="down"?"critical":rawStatus==="warning"?"warning":"healthy";}
function renderServerVisualPanel(){const dashboard=state.dashboard||{};const server=dashboard.server||{};const nodes=coerceList(server.clusterNodes);const rows=nodes.length?nodes:[Object.assign({nodeName:"Primary",configuredHost:(server.target||{}).host||((selectedEnvironmentRecord()||{}).server||{}).host,actualHostname:server.actualHostname,reachable:server.reachable,health:server.health},server)];if(!rows.length)return"";return`<section class="panel server-visual-panel"><div class="panel-header"><div><h3 class="panel-title">Infrastructure Health Map</h3><p class="panel-copy">A quick visual read of load, memory, disk, and host reachability before drilling into the raw tables.</p></div></div><div class="server-visual-grid">${rows.map(function(row,index){const uptime=row.uptime||{};const memory=row.memory||{};const rootDisk=row.rootDisk||{};const refreshDisk=row.refreshDisk||{};const cpuCount=parseFloat(uptime.cpuCount)||1;const loadPct=Math.max(0,Math.min(100,(parseFloat(uptime.load1)||0)/cpuCount*100));const tone=nodeVisualStatusTone(row);return`<article class="server-visual-card is-${escapeHtml(tone)}"><div class="server-visual-head"><div><span>${escapeHtml(row.nodeName||`Node ${index+1}`)}</span><strong>${escapeHtml(row.actualHostname||row.configuredHost||"-")}</strong></div>${renderStatusPill(tone,tone==="healthy"?"Healthy":tone==="warning"?"Warning":"Critical")}</div>${renderServerMetricBar("Load",loadPct,loadPct>=80?"critical":loadPct>=60?"warning":"healthy")}${renderServerMetricBar("Memory",memory.usedPercent,memory.usedPercent>=90?"critical":memory.usedPercent>=75?"warning":"healthy")}${renderServerMetricBar("Root Disk",rootDisk.usedPercent,rootDisk.usedPercent>=90?"critical":rootDisk.usedPercent>=80?"warning":"healthy")}${refreshDisk&&refreshDisk.usedPercent!=null?renderServerMetricBar("Refresh Disk",refreshDisk.usedPercent,refreshDisk.usedPercent>=90?"critical":refreshDisk.usedPercent>=80?"warning":"healthy"):""}</article>`;}).join("")}</div></section>`;}
