function renderPageContent(){if(!state.appShell)return renderEmptyPanel("Loading console","The dashboard is fetching its current state.");if(isAdministrationContext()){if(state.activeSection==="admin-notifications")return renderNotificationsPage();if(state.activeSection==="admin-help")return renderHelpPage();return renderEnvironmentRegistryPage();}if(!state.dashboard)return renderEmptyPanel("Loading environment","The selected environment dashboard is still being collected.");if(state.activeSection==="env-server")return renderServerMetricsPageWithVisuals();if(state.activeSection==="env-applications")return renderApplicationMetricsPage();if(state.activeSection==="env-logscope")return renderLogScopePage();return renderCombinedOverviewPage();}
document.addEventListener("click",function(event){const maximizeButton=event.target.closest("[data-logscope-analysis-maximize]");if(maximizeButton){state.logScope=Object.assign({},currentLogScopeState(),{analysisMaximized:!currentLogScopeState().analysisMaximized});render();return;}const clearFiltersButton=event.target.closest("[data-logscope-clear-filters]");if(clearFiltersButton){state.logScope=Object.assign({},currentLogScopeState(),{filterText:"",filterLogger:"",analysisOnlyProblems:false,selectedLogLevels:LOGSCOPE_LEVEL_ORDER.slice(),selectedLoggers:null});render();return;}const levelAll=event.target.closest("[data-logscope-level-select-all]");if(levelAll){const entries=logScopeEntries(currentLogScopeState());const counts=logScopeLevelCounts(entries);const available=LOGSCOPE_LEVEL_ORDER.filter(function(level){return(counts[level]||0)>0;});state.logScope=Object.assign({},currentLogScopeState(),{selectedLogLevels:levelAll.getAttribute("data-logscope-level-select-all")==="all"?available:[]});render();return;}const loggerAll=event.target.closest("[data-logscope-logger-select-all]");if(loggerAll){const rows=logScopeLoggerCounts(logScopeEntries(currentLogScopeState()));state.logScope=Object.assign({},currentLogScopeState(),{selectedLoggers:loggerAll.getAttribute("data-logscope-logger-select-all")==="all"?rows.map(function(row){return row.name;}):[]});render();return;}const quickSearch=event.target.closest("[data-logscope-quick-search]");if(quickSearch){state.logScope=Object.assign({},currentLogScopeState(),{filterText:quickSearch.getAttribute("data-logscope-quick-search")||""});render();return;}});
