function defaultLogScopeState(envId){return{environmentId:envId||"",profiles:[],activeProfileId:"",activeGroupId:"",files:[],selectedFile:"",logText:"",isLoading:false,isReading:false,error:"",viewMode:"tail",tailLines:500,latestFirst:false,logReadMode:"",fullAnalysisOpen:false,analysisMaximized:false,filterText:"",filterLevel:"all",filterLogger:"",analysisOnlyProblems:false,fileFilter:"",selectedLogLevels:LOGSCOPE_LEVEL_ORDER.slice(),selectedLoggers:null,viewerFilterText:"",viewerLevel:"all",terminalTheme:"dark",terminalWrap:false,terminalFontSize:14};}
function percentNumber(value){const number=parseFloat(value);return Number.isFinite(number)?Math.max(0,Math.min(100,number)):0;}
function compactMetricValue(value,suffix){const number=parseFloat(value);if(!Number.isFinite(number))return"-";return`${Math.round(number)}${suffix||""}`;}
function renderServerGauge(label,value,tone,detail){const percent=percentNumber(value);return`<div class="server-gauge-card is-${escapeHtml(tone||"neutral")}" style="--gauge-stop:${percent}%"><div class="server-gauge-ring"><span>${escapeHtml(compactMetricValue(percent,"%"))}</span></div><div><strong>${escapeHtml(label)}</strong><small>${escapeHtml(detail||"")}</small></div></div>`;}
function renderServerMicroMetric(label,value){return`<div class="server-micro-metric"><span>${escapeHtml(label)}</span><strong>${escapeHtml(formatValue(value,"-"))}</strong></div>`;}
function renderServerVisualPanel(){const dashboard=state.dashboard||{};const server=dashboard.server||{};const nodes=coerceList(server.clusterNodes);const rows=nodes.length?nodes:[Object.assign({nodeName:"Primary",configuredHost:(server.target||{}).host||((selectedEnvironmentRecord()||{}).server||{}).host,actualHostname:server.actualHostname,reachable:server.reachable,health:server.health},server)];if(!rows.length)return"";const healthyCount=rows.filter(function(row){return nodeVisualStatusTone(row)==="healthy";}).length;const warningCount=rows.filter(function(row){return nodeVisualStatusTone(row)==="warning";}).length;const criticalCount=rows.length-healthyCount-warningCount;const worstTone=criticalCount?"critical":warningCount?"warning":"healthy";return`<section class="panel server-visual-panel is-modern"><div class="server-map-hero is-${escapeHtml(worstTone)}"><div><p class="eyebrow">Infrastructure Health Map</p><h3>${escapeHtml(rows.length)} ${rows.length===1?"host":"hosts"} monitored</h3><p>Fast visual read of reachability, load, memory, and disk pressure before drilling into the tables.</p></div><div class="server-map-score"><span>${escapeHtml(healthyCount)}/${escapeHtml(rows.length)}</span><small>healthy</small></div><div class="server-map-legend"><span class="is-healthy">Healthy ${escapeHtml(healthyCount)}</span><span class="is-warning">Warning ${escapeHtml(warningCount)}</span><span class="is-critical">Critical ${escapeHtml(criticalCount)}</span></div></div><div class="server-visual-grid">${rows.map(function(row,index){const uptime=row.uptime||{};const memory=row.memory||{};const rootDisk=row.rootDisk||{};const refreshDisk=row.refreshDisk||{};const cpuCount=parseFloat(uptime.cpuCount)||1;const loadPct=percentNumber((parseFloat(uptime.load1)||0)/cpuCount*100);const memoryPct=percentNumber(memory.usedPercent);const rootPct=percentNumber(rootDisk.usedPercent);const refreshPct=refreshDisk&&refreshDisk.usedPercent!=null?percentNumber(refreshDisk.usedPercent):null;const tone=nodeVisualStatusTone(row);return`<article class="server-visual-card is-${escapeHtml(tone)}"><div class="server-node-banner"><span class="server-node-orb"></span><div><span>${escapeHtml(row.nodeName||`Node ${index+1}`)}</span><strong>${escapeHtml(row.actualHostname||row.configuredHost||"-")}</strong><small>${escapeHtml(row.configuredHost&&row.actualHostname&&row.configuredHost!==row.actualHostname?row.configuredHost:row.configuredHost||"")}</small></div>${renderStatusPill(tone,tone==="healthy"?"Healthy":tone==="warning"?"Warning":"Critical")}</div><div class="server-gauge-row">${renderServerGauge("Load",loadPct,loadPct>=80?"critical":loadPct>=60?"warning":"healthy",`${formatValue(uptime.load1,"-")} / ${formatValue(cpuCount,"-")} CPU`)}${renderServerGauge("Memory",memoryPct,memoryPct>=90?"critical":memoryPct>=75?"warning":"healthy",formatPercent(memory.usedPercent))}${renderServerGauge("Root Disk",rootPct,rootPct>=90?"critical":rootPct>=80?"warning":"healthy",formatPercent(rootDisk.usedPercent))}${refreshPct!=null?renderServerGauge("Refresh Disk",refreshPct,refreshPct>=90?"critical":refreshPct>=80?"warning":"healthy",formatPercent(refreshDisk.usedPercent)):""}</div><div class="server-micro-grid">${renderServerMicroMetric("CPU",uptime.cpuCount)}${renderServerMicroMetric("Uptime",uptime.uptimeSeconds?`${Math.round((parseFloat(uptime.uptimeSeconds)||0)/3600)} hrs`:"-")}${renderServerMicroMetric("SSH",row.reachable?"Reachable":"Unreachable")}</div></article>`;}).join("")}</div></section>`;}
function opatchRowText(item){return`${(item||{}).patchId||""} ${(item||{}).description||""} ${(item||{}).recommendation||""}`;}
function opatchIsStackBundleRow(item){return/\bIDM\s+STACK\s+PATCH\s+BUNDLE\b|\bSTACK\s+PATCH\s+BUNDLE\b|\bSPB\b/i.test(opatchRowText(item));}
function opatchIsBundleRow(item){return opatchIsStackBundleRow(item)||/\bBUNDLE\s+PATCH\b|\bPATCH\s+SET\s+UPDATE\b|\bCUMULATIVE\s+PATCH\b/i.test(opatchRowText(item));}
function opatchPatchDisplay(item){const patchId=String((item||{}).patchId||"").trim();const description=String((item||{}).description||"").trim();if(description&&patchId&&description.indexOf(patchId)===-1)return`${description} (Patch ${patchId})`;return description||patchId||"-";}
function opatchInstalledRows(inventory,recommendation){const patches=coerceList((inventory||{}).patches).filter(function(item){return String(item.patchId||"").trim();});if(patches.length)return patches;return coerceList((recommendation||{}).comparisonRows).filter(function(item){return String(item.patchId||"").trim()&&String(item.description||"").toLowerCase()!=="not installed";});}
function opatchCurrentLevelInfo(inventory,recommendation){const rec=recommendation||{};const rows=opatchInstalledRows(inventory,rec);const spb=rows.find(opatchIsStackBundleRow);if(spb)return{label:"Current Stack Bundle",value:opatchPatchDisplay(spb)};const bundle=rows.find(opatchIsBundleRow);if(bundle)return{label:"Current Bundle Patch",value:opatchPatchDisplay(bundle)};const base=rec.version||opatchDetectedVersion(inventory,rec)||"-";return{label:"Current Version",value:rows.length?`${base} base level with one-off patches`:`${base} base installation`};}
function opatchPatchRowClass(item){const status=String((item||{}).recommendationStatus||"none").toLowerCase();const classes=[`is-${status||"none"}`];if(opatchIsStackBundleRow(item))classes.push("is-stack-bundle");if(status==="missing"&&opatchIsStackBundleRow(item))classes.push("is-stack-missing");return classes.join(" ");}
function renderOpatchCurrentLevel(inventory,recommendation){const rec=recommendation||{};const current=opatchCurrentLevelInfo(inventory,rec);const opatchVersion=opatchVersionValue(inventory,"OPatch version")||opatchVersionValue(inventory,"OPatch Installer Version")||"-";const recommended=rec.latestPatchId?`${rec.latestPatchId} - ${rec.latestRelease||"Latest SPB"}`:"-";const tone=patchRecommendationNeedsAction(rec)?"warning":"healthy";return`<div class="opatch-current-strip is-${tone}"><div class="opatch-current-card is-primary"><span>${escapeHtml(current.label)}</span><strong>${escapeHtml(current.value)}</strong></div><div class="opatch-current-card"><span>Current OPatch</span><strong>${escapeHtml(opatchVersion)}</strong></div><div class="opatch-current-card"><span>Recommended Level</span><strong>${escapeHtml(recommended)}</strong></div></div>`;}
function renderKa754Recommendation(recommendation){const rec=recommendation||{};if(!rec.latestPatchId)return"";const components=coerceList(rec.components).join(", ")||"FMW";const needsAction=patchRecommendationNeedsAction(rec);const action=needsAction?"Review Oracle KM KA754 and apply latest SPB":"Latest Stack Patch Bundle applied";const kaLink=`<a class="support-link" href="${KA754_URL}" target="_blank" rel="noopener noreferrer">KA754</a>`;const safeComponents=escapeHtml(components);const safeVersion=escapeHtml(rec.version||"");const safeRelease=escapeHtml(rec.latestRelease||"-");const safePatch=escapeHtml(rec.latestPatchId);const detail=needsAction?`Please review Oracle KM document ${kaLink} and apply the latest available ${safeVersion} Stack Patch Bundle for ${safeComponents}, currently ${safeRelease} Patch ${safePatch}.`:`Installed patches match the latest Stack Patch Bundle level documented in ${kaLink}: ${safeRelease} Patch ${safePatch}.`;const tone=needsAction?"warning":"healthy";return`<div class="subsection-block patch-recommendation-block is-${tone==="healthy"?"healthy":"warning"}"><h4>Oracle KM KA754 Patch Recommendation</h4>${renderDefinitionList([{key:"Patch Status",htmlValue:renderStatusPill(tone==="healthy"?"healthy":"warning",patchRecommendationStatusText(rec)),tone:tone},{key:"Action",value:action,tone:tone},{key:"Base Version",value:rec.version||"-"},{key:"Recommended Patch",value:`${rec.latestPatchId} - ${rec.latestRelease||"Latest SPB"}`,tone:tone},{key:"Recommendation",htmlValue:detail,tone:tone}])}</div>`;}
function renderOpatchInventoryPanel(opatch,title,copy){const inventory=opatch||{};const versions=coerceList(inventory.versions).filter(function(item){return String(item.key||"").toLowerCase()!=="oui version";});const distributions=coerceList(inventory.distributions);const products=coerceList(inventory.products);const patches=coerceList(inventory.patches);const recommendation=inventory.recommendation||{};const comparisonRows=coerceList(inventory.patchComparisonRows).length?coerceList(inventory.patchComparisonRows):coerceList(recommendation.comparisonRows);const rows=comparisonRows.length?comparisonRows:patches.map(function(item){const row=Object.assign({},item);row.recommendation="-";row.recommendationStatus="none";return row;});const versionItems=versions.map(function(item){return{key:item.key||"Version",value:item.value||"-"};});distributions.forEach(function(value,index){versionItems.push({key:index?"OUI Distribution "+(index+1):"OUI Distribution",value:value});});if(inventory.durationSeconds)versionItems.push({key:"OPatch Duration",value:`${inventory.durationSeconds} sec`});const productRows=products.length?`<div class="table-wrap patch-product-table"><table><thead><tr><th>Installed Product</th><th>Version</th></tr></thead><tbody>${products.map(function(item){return`<tr><td>${escapeHtml(item.name||"-")}</td><td>${escapeHtml(item.version||"-")}</td></tr>`;}).join("")}</tbody></table></div>`:"";const patchRows=rows.length?`<div class="table-wrap"><table><thead><tr><th>Patch</th><th>Description</th><th>Applied On</th><th>Recommended</th></tr></thead><tbody>${rows.map(function(item){return`<tr class="patch-row ${escapeHtml(opatchPatchRowClass(item))}"><td>${escapeHtml(item.patchId||"-")}</td><td>${escapeHtml(item.description||"-")}</td><td>${escapeHtml(item.appliedOn||"-")}</td><td>${patchRecommendationCell(item)}</td></tr>`;}).join("")}</tbody></table></div>`:renderEmptyPanel("No OPatch rows",inventory.error||"No installed interim patches were returned by OPatch lsinventory or OPatch lspatches.");return`<section class="panel patch-inventory-panel"><div class="panel-header"><div><h3 class="panel-title">${escapeHtml(title)}</h3><p class="panel-copy">${escapeHtml(copy)}</p></div></div>${inventory.error?`<p class="table-note">${escapeHtml(inventory.error)}</p>`:""}${inventory.warning?`<p class="table-note">${escapeHtml(inventory.warning)}</p>`:""}${inventory.parserNote?`<p class="table-note">${escapeHtml(inventory.parserNote)}</p>`:""}${renderOpatchCurrentLevel(inventory,recommendation)}${patchRecommendationNotice(recommendation)}${renderKa754Recommendation(recommendation)}${versionItems.length?renderDefinitionList(versionItems):""}${productRows}${patchRows}${inventory.command?`<p class="table-note">Command: ${escapeHtml(inventory.command)}</p>`:""}${inventory.lspatchesCommand?`<p class="table-note">Fallback command: ${escapeHtml(inventory.lspatchesCommand)}</p>`:""}${inventory.distributionCommand?`<p class="table-note">Distribution command: ${escapeHtml(inventory.distributionCommand)}</p>`:""}</section>`;}
