function logScopeViewerFilteredText(logState){let lines=String(logState.logText||"").split(/\r?\n/);const text=String(logState.viewerFilterText||"").trim().toLowerCase();const level=String(logState.viewerLevel||"all").toUpperCase();if(level!=="ALL")lines=lines.filter(function(line){return logScopeLineLevel(line)===level;});if(text)lines=lines.filter(function(line){return line.toLowerCase().includes(text);});return lines.join("\n");}
function renderLogScopeTerminal(text,emptyCopy,isRunning,mode){const logState=currentLogScopeState();const body=String(text||"").trim()||String(emptyCopy||"");const title=mode==="complete"?"Complete Log":"Log Tail";const theme=String(logState.terminalTheme||"dark")==="light"?"light":"dark";const fontSize=Math.max(11,Math.min(20,parseInt(logState.terminalFontSize,10)||14));return`<div class="terminal-window logscope-terminal is-${escapeHtml(theme)} ${logState.terminalWrap?"is-wrap":""}" style="--log-font-size:${fontSize}px"><div class="terminal-bar"><div class="terminal-chrome" aria-hidden="true"><span class="terminal-dot"></span><span class="terminal-dot"></span><span class="terminal-dot"></span></div><strong class="terminal-title">${escapeHtml(title)}</strong>${isRunning?'<span class="terminal-live"><span class="terminal-live-spinner" aria-hidden="true"></span>Loading</span>':""}</div><pre class="terminal-body">${escapeHtml(body)}</pre></div>`;}
function renderLogScopeViewer(logState){const selected=findLogScopeSelection(logState.profiles,logState.activeProfileId,logState.activeGroupId);const title=logState.selectedFile?logState.selectedFile:"Log Reader";const tailLines=parseInt(logState.tailLines,10)||500;const canRead=Boolean(logState.selectedFile&&selected.group);const filteredText=logScopeViewerFilteredText(logState);const matchCount=logState.logText?String(filteredText||"").split(/\r?\n/).filter(function(line){return line.trim();}).length:0;const totalCount=logState.logText?String(logState.logText||"").split(/\r?\n/).filter(function(line){return line.trim();}).length:0;if(logState.isReading)return`<section class="panel logscope-viewer-panel">${renderLogScopeTerminal("Loading selected log file...","Loading selected log file...",true,logState.logReadMode)}</section>`;return`<section class="panel logscope-viewer-panel"><div class="logscope-reader-top"><div><p class="eyebrow">${selected.group?escapeHtml(selected.group.product||selected.group.productCode||"Logs"):"LogScope"}</p><h3 class="panel-title">${escapeHtml(title)}</h3><p class="panel-copy">${selected.group?escapeHtml(selected.group.directory):"Choose a source, then double-click a log file from the left pane."}</p></div><div class="logscope-reader-status">${logState.logText?`${escapeHtml(matchCount)} / ${escapeHtml(totalCount)} lines`:"Idle"}</div></div><div class="logscope-control-bar"><input class="input-field" type="search" data-logscope-viewer-filter-text placeholder="Filter text" value="${escapeHtml(logState.viewerFilterText||"")}"><select class="compact-select" data-logscope-viewer-level-filter>${logScopeViewerLevelOptions(logState.viewerLevel)}</select><select class="compact-select" data-logscope-terminal-theme><option value="dark" ${String(logState.terminalTheme||"dark")==="dark"?"selected":""}>Dark terminal</option><option value="light" ${String(logState.terminalTheme||"dark")==="light"?"selected":""}>Light terminal</option></select><label class="checkbox-row"><input type="checkbox" data-logscope-wrap ${logState.terminalWrap?"checked":""}> Wrap</label><div class="font-stepper"><button class="button" type="button" data-logscope-font-step="-1">-</button><span>${escapeHtml((parseInt(logState.terminalFontSize,10)||14)+"px")}</span><button class="button" type="button" data-logscope-font-step="1">+</button></div><label class="checkbox-row"><input type="checkbox" data-logscope-latest-first ${logState.latestFirst?"checked":""}> Newest first</label><select class="compact-select" data-logscope-tail-lines><option value="200" ${tailLines===200?"selected":""}>200 lines</option><option value="500" ${tailLines===500?"selected":""}>500 lines</option><option value="1000" ${tailLines===1000?"selected":""}>1000 lines</option><option value="2000" ${tailLines===2000?"selected":""}>2000 lines</option><option value="5000" ${tailLines===5000?"selected":""}>5000 lines</option></select><button class="button" type="button" data-logscope-tail-refresh ${canRead?"":"disabled"}>Tail</button><button class="button is-primary" type="button" data-logscope-load-complete ${canRead?"":"disabled"}>Load Complete</button><button class="button" type="button" data-logscope-open-analysis ${canRead?"":"disabled"}>Detailed Log Analysis</button></div>${!canRead?renderEmptyPanel("No log file selected","Select a file in the left pane. Double-click opens the complete log here; Tail refreshes only the latest lines."):renderLogScopeTerminal(filteredText,logState.logReadMode==="tail"?"Click Tail to read the latest lines.":"Double-click a file or click Load Complete to read the full log.",false,logState.logReadMode)}</section>`;}
function renderLogScopeSourceList(logState){const profiles=coerceList(logState.profiles);if(logState.isLoading)return renderEmptyPanel("Loading log sources","Reading log locations from this dashboard connection profile.");if(!profiles.length)return renderEmptyPanel("No log sources loaded","Click Load Log Sources after the collector has run, or confirm the connection profile has product paths such as DOMAIN_HOME, ORACLE_HOME, OUD instance home, or OAA mounted log path.");return`<div class="logscope-source-strip is-enhanced">${profiles.map(function(profile){return coerceList(profile.logGroups).map(function(group){const active=profile.id===logState.activeProfileId&&group.id===logState.activeGroupId;return`<button class="logscope-source-card ${active?"is-active":""}" type="button" data-logscope-source data-profile-id="${escapeHtml(profile.id)}" data-group-id="${escapeHtml(group.id)}"><span class="logscope-source-product">${escapeHtml(group.product||group.productCode||"Logs")}</span><strong>${escapeHtml(group.name)}</strong><small>${escapeHtml(profile.host)}:${escapeHtml(formatValue(profile.port,"22"))}</small><code>${escapeHtml(group.directory)}</code></button>`;}).join("");}).join("")}</div>`;}
function renderLogScopeFileTable(logState){if(logState.isLoading)return renderEmptyPanel("Loading files","The dashboard is listing files over SSH.");const selected=findLogScopeSelection(logState.profiles,logState.activeProfileId,logState.activeGroupId);if(!selected.group)return renderEmptyPanel("Choose a server or log source","Select a source at the top to load its log files here.");if(logState.error)return renderEmptyPanel("Log source unavailable",logState.error);const files=coerceList(logState.files);if(!files.length)return renderEmptyPanel("No files returned",`No files were returned from ${selected.group.directory}.`);const visible=logScopeVisibleFiles(logState);return`<div class="logscope-file-toolbar"><input class="input-field" type="search" data-logscope-file-filter placeholder="Filter log files..." value="${escapeHtml(logState.fileFilter||"")}"><span>${visible.length} of ${files.length} files</span></div>${!visible.length?renderEmptyPanel("No matching files","Clear the file filter to show all files for this source."):`<div class="logscope-file-list is-enhanced">${visible.map(function(file){const active=file.name===logState.selectedFile;const ext=(String(file.name||"").split(".").pop()||"log").slice(0,6);return`<button class="logscope-file-row ${active?"is-selected":""}" type="button" data-logscope-file-select="${escapeHtml(file.name)}" title="Double-click to open the complete log"><span class="logscope-file-icon">${escapeHtml(ext)}</span><span class="logscope-file-name">${escapeHtml(file.name)}</span><span class="logscope-file-meta">${escapeHtml(file.size||"-")} | ${escapeHtml(file.modified||"-")}</span><span class="logscope-file-open" data-logscope-file-open="${escapeHtml(file.name)}">Open</span></button>`;}).join("")}</div>`}`;}
document.addEventListener("click",async function(event){const openButton=event.target.closest("[data-logscope-file-open]");if(openButton){event.preventDefault();event.stopImmediatePropagation();await readLogScopeFile(openButton.getAttribute("data-logscope-file-open"),{complete:true});return;}const row=event.target.closest("[data-logscope-file-select]");if(row&&event.detail>=2){event.preventDefault();event.stopImmediatePropagation();await readLogScopeFile(row.getAttribute("data-logscope-file-select"),{complete:true});return;}},true);
