document.addEventListener("click",function(event){const fontButton=event.target.closest("[data-logscope-font-step]");if(!fontButton)return;const step=parseInt(fontButton.getAttribute("data-logscope-font-step"),10)||0;const current=parseInt(currentLogScopeState().terminalFontSize,10)||14;state.logScope=Object.assign({},currentLogScopeState(),{terminalFontSize:Math.max(11,Math.min(20,current+step))});render();});
function processTokenValue(command,pattern){const match=String(command||"").match(pattern);return match?match[1]:"";}
function processBasename(path){const value=String(path||"").trim();if(!value)return"-";const clean=value.replace(/\\/g,"/");return clean.split("/").filter(Boolean).pop()||clean;}
function processShortPath(path){const value=String(path||"").trim();if(!value)return"";const clean=value.replace(/\\/g,"/");const parts=clean.split("/").filter(Boolean);if(parts.length<=3)return clean;return`.../${parts.slice(-3).join("/")}`;}
function parseMatchedProcess(item){if(item&&typeof item==="object"){const command=String(item.command||item.cmd||item.raw||"").trim();return Object.assign({raw:command,command:command,user:item.user||item.owner||"-",pid:item.pid||"-"},item);}const raw=String(item||"").trim();const match=raw.match(/^(\S+)\s+(\d+)\s+([\s\S]*)$/);const user=match?match[1]:"-";const pid=match?match[2]:"-";const command=match?match[3]:raw;const serverName=processTokenValue(command,/(?:-Dweblogic\.Name=|weblogic\.Name=)([^\s]+)/);const domainHome=processTokenValue(command,/-D(?:domain\.home|weblogic\.RootDirectory)=([^\s]+)/);const javaHome=processTokenValue(command,/-Dweblogic\.nodemanager\.JavaHome=([^\s]+)/)||processTokenValue(command,/^\s*(\/[^\s]*\/bin\/java)\b/);const xms=processTokenValue(command,/-Xms([^\s]+)/);const xmx=processTokenValue(command,/-Xmx([^\s]+)/);let role="Process";let product="Server";let tone="neutral";if(/grep\s+-E|grep\s+/i.test(command)){role="Matcher Command";product="Collector";tone="muted";}else if(/weblogic\.NodeManager/i.test(command)){role="Node Manager";product="WebLogic";tone="info";}else if(/startWebLogic/i.test(command)){role="Start Script";product="WebLogic";tone="info";}else if(serverName){role=serverName==="AdminServer"?"Admin Server":"Managed Server";product="WebLogic";tone=serverName==="AdminServer"?"admin":"managed";}else if(/oidldapd/i.test(command)){role="OID LDAP Process";product="OID";tone="directory";}else if(/java/i.test(command)){role="Java Process";product="Java";tone="info";}const firstToken=String(command||"").split(/\s+/)[0]||"-";return{raw:raw,command:command,user:user,pid:pid,role:role,product:product,tone:tone,serverName:serverName,domainHome:domainHome,javaHome:javaHome,xms:xms,xmx:xmx,executable:processBasename(firstToken)};}
function processFact(label,value){if(value==null||String(value).trim()==="")return"";return`<div class="process-fact"><span>${escapeHtml(label)}</span><strong>${escapeHtml(value)}</strong></div>`;}
function processCardTitle(row,index){if(row.serverName)return row.serverName;if(row.role&&row.role!=="Process")return row.role;return`Process ${index+1}`;}
function renderProcessCards(rows){return rows.map(function(row,index){const memory=[row.xms?`Xms ${row.xms}`:"",row.xmx?`Xmx ${row.xmx}`:""].filter(Boolean).join(" / ");const title=processCardTitle(row,index);return`<article class="process-card is-${escapeHtml(row.tone||"neutral")}"><div class="process-card-head"><div><p class="eyebrow">${escapeHtml(row.product||"Server")}</p><h4>${escapeHtml(title)}</h4></div><span class="process-role">${escapeHtml(row.role||"Process")}</span></div><div class="process-chip-row"><span>PID ${escapeHtml(formatValue(row.pid,"-"))}</span><span>${escapeHtml(row.user||"-")}</span><span>${escapeHtml(row.executable||processBasename(row.command))}</span></div><div class="process-fact-grid">${processFact("Domain",processShortPath(row.domainHome))}${processFact("Java",processShortPath(row.javaHome))}${processFact("Memory",memory)}${processFact("Command",processBasename(String(row.command||"").split(/\s+/)[0]||""))}</div><details class="process-command"><summary>Command line</summary><pre>${escapeHtml(row.command||row.raw||"-")}</pre></details></article>`;}).join("");}
function renderCodeList(lines,emptyCopy){const rows=coerceList(lines).map(parseMatchedProcess).filter(function(row){return row.raw||row.command;});if(!rows.length)return`<p class="table-note">${escapeHtml(emptyCopy||"No matching processes were discovered.")}</p>`;const weblogicCount=rows.filter(function(row){return row.product==="WebLogic";}).length;const managedCount=rows.filter(function(row){return row.role==="Managed Server";}).length;const utilityCount=rows.filter(function(row){return row.tone==="muted"||row.role==="Start Script"||row.role==="Matcher Command";}).length;return`<div class="process-dashboard"><div class="process-summary-strip"><div><span>Total processes</span><strong>${escapeHtml(rows.length)}</strong></div><div><span>WebLogic</span><strong>${escapeHtml(weblogicCount)}</strong></div><div><span>Managed servers</span><strong>${escapeHtml(managedCount)}</strong></div><div><span>Scripts / matchers</span><strong>${escapeHtml(utilityCount)}</strong></div></div><div class="process-card-grid">${renderProcessCards(rows)}</div></div>`;}
function defaultLogScopeState(envId){return{environmentId:envId||"",profiles:[],activeProfileId:"",activeGroupId:"",files:[],selectedFile:"",logText:"",isLoading:false,isReading:false,error:"",viewMode:"tail",tailLines:500,latestFirst:false,logReadMode:"",fullAnalysisOpen:false,analysisMaximized:false,filterText:"",filterLevel:"all",filterLogger:"",analysisOnlyProblems:false,javaStacksOnly:false,fileFilter:"",selectedLogLevels:LOGSCOPE_LEVEL_ORDER.slice(),selectedLoggers:null,viewerFilterText:"",viewerLevel:"all",terminalTheme:"dark",terminalWrap:false,terminalFontSize:14};}
function logScopeByteCount(file){const value=file&&file.sizeBytes!=null?file.sizeBytes:file&&file.bytes!=null?file.bytes:file&&file.size!=null?file.size:null;if(value==null||String(value).trim()==="")return null;if(typeof value==="number"&&Number.isFinite(value))return value;const text=String(value).replace(/,/g,"").trim();const match=text.match(/^([\d.]+)\s*([kmgt]?b)?$/i);if(match){const number=parseFloat(match[1]);if(!Number.isFinite(number))return null;const unit=String(match[2]||"b").toLowerCase();const multiplier=unit==="gb"?1024*1024*1024:unit==="mb"?1024*1024:unit==="kb"?1024:unit==="tb"?1024*1024*1024*1024:1;return number*multiplier;}const fallback=parseFloat(text.replace(/[^\d.]/g,""));return Number.isFinite(fallback)?fallback:null;}
function logScopeFileSizeLabel(file){const bytes=logScopeByteCount(file);if(bytes==null)return escapeHtml(file&&file.size?file.size:"-");if(bytes<=0)return"0MB";const mb=bytes/(1024*1024);if(mb<0.01)return"0.01 MB";if(mb<10)return`${mb.toFixed(2)} MB`;if(mb<100)return`${mb.toFixed(1)} MB`;return`${Math.round(mb)} MB`;}
function logScopeFileExt(name){const ext=(String(name||"").split(".").pop()||"log").slice(0,6);return ext&&ext!==String(name||"")?ext:"log";}
function renderLogScopeFileTable(logState){if(logState.isLoading)return renderEmptyPanel("Loading files","The dashboard is listing files over SSH.");const selected=findLogScopeSelection(logState.profiles,logState.activeProfileId,logState.activeGroupId);if(!selected.group)return renderEmptyPanel("Choose a server or log source","Select a source at the top to load its log files here.");if(logState.error)return renderEmptyPanel("Log source unavailable",logState.error);const files=coerceList(logState.files);if(!files.length)return renderEmptyPanel("No files returned",`No files were returned from ${selected.group.directory}.`);const visible=logScopeVisibleFiles(logState);return`<div class="logscope-file-toolbar"><input class="input-field" type="search" data-logscope-file-filter placeholder="Filter log files..." value="${escapeHtml(logState.fileFilter||"")}"><span>${visible.length} of ${files.length} files</span></div>${!visible.length?renderEmptyPanel("No matching files","Clear the file filter to show all files for this source."):`<div class="logscope-file-list is-enhanced is-mb-sized">${visible.map(function(file){const active=file.name===logState.selectedFile;const bytes=logScopeByteCount(file);const empty=bytes!=null&&bytes<=0;return`<button class="logscope-file-row ${active?"is-selected":""} ${empty?"is-empty-file":""}" type="button" data-logscope-file-select="${escapeHtml(file.name)}" title="Double-click to open the complete log"><span class="logscope-file-icon">${escapeHtml(logScopeFileExt(file.name))}</span><span class="logscope-file-name">${escapeHtml(file.name)}</span><span class="logscope-file-meta"><strong class="logscope-file-size ${empty?"is-empty":""}">${logScopeFileSizeLabel(file)}</strong><span>${escapeHtml(file.modified||"-")}</span></span><span class="logscope-file-open" data-logscope-file-open="${escapeHtml(file.name)}">Open</span></button>`;}).join("")}</div>`}`;}
function renderLogScopePage(){const record=selectedEnvironmentRecord()||{};const dashboard=state.dashboard||{};const logState=currentLogScopeState();const profiles=coerceList(logState.profiles);const sourceCount=profiles.reduce(function(total,profile){return total+coerceList(profile.logGroups).length;},0);const hosts=uniqueList(profiles.map(function(profile){return profile.host;}));const selected=findLogScopeSelection(profiles,logState.activeProfileId,logState.activeGroupId);return`<div class="content-stack"><section class="panel logscope-sources-panel"><div class="panel-header"><div><h3 class="panel-title">Servers And Log Sources</h3><p class="panel-copy">Choose a server or product log source first. Its log files load in the left pane below.</p></div><div class="panel-actions logscope-refresh-actions"><button class="button logscope-action-button is-source" type="button" data-load-logscope-sources ${logState.isLoading?"disabled":""}><span>${profiles.length?"Refresh Log Sources":"Load Log Sources"}</span><small>${profiles.length?`${sourceCount} sources`:"discover"}</small></button>${selected.group?`<button class="button logscope-action-button is-files" type="button" data-refresh-logscope-files ${logState.isLoading?"disabled":""}><span>Refresh Files</span><small>${coerceList(logState.files).length} loaded</small></button>`:""}</div></div>${renderLogScopeSourceList(logState)}</section>${renderSummaryTiles([{label:"Log Hosts",value:hosts.length,copy:"Servers with product log directories."},{label:"Log Sources",value:sourceCount,copy:"WebLogic, OUD, OID, OAA, and product log locations."},{label:"Selected Source",value:selected.group?selected.group.name:"-",copy:selected.profile?selected.profile.host:"Choose a source to load files."},{label:"Files Loaded",value:coerceList(logState.files).length,copy:"Files returned for the selected directory."}])}<div class="logscope-console-layout"><aside class="panel logscope-file-pane"><div class="panel-header"><div><h3 class="panel-title">Log Files</h3><p class="panel-copy">${selected.group?`Double-click a file from ${escapeHtml(selected.group.name)} to open the complete log.`:"Select a source above to list files."}</p></div></div>${renderLogScopeFileTable(logState)}</aside><main class="logscope-reader-pane">${renderLogScopeViewer(logState)}</main></div>${renderOaaLogScopeCommands(record,dashboard)}${renderLogScopeAnalysisModal(logState)}</div>`;}
function logScopeJavaStackHit(entry){const line=String((entry&&entry.line)||"");return/\b(?:Exception|Throwable|Caused by:|StackTrace|ORA-\d+|BEA-\d+|IAM-\d+|ODL-\d+|J2EE\s+JMX|NullPointer|ClassNotFound|NoClassDefFound|SQLException|SocketTimeout|ConnectException)\b/i.test(line)||/^\s*at\s+(?:java|javax|jakarta|oracle|weblogic|com)\./.test(line);}
function logScopeFilteredEntries(logState){const entries=logScopeEntries(logState);const counts=logScopeLevelCounts(entries);const loggerRows=logScopeLoggerCounts(entries);const selectedLevels=logScopeSelectedLevels(logState,counts);const selectedLoggers=logScopeSelectedLoggers(logState,loggerRows);const text=String(logState.filterText||"").trim().toLowerCase();const loggerContains=String(logState.filterLogger||"").trim().toLowerCase();return entries.filter(function(entry){const logger=entry.logger||"Unparsed logger";if(logState.analysisOnlyProblems&&!entry.problem)return false;if(logState.javaStacksOnly&&!logScopeJavaStackHit(entry))return false;if(selectedLevels.length&&!selectedLevels.includes(entry.level))return false;if(selectedLoggers.length&&!selectedLoggers.includes(logger))return false;if(loggerContains&&logger.toLowerCase().indexOf(loggerContains)===-1)return false;if(text&&entry.line.toLowerCase().indexOf(text)===-1)return false;return true;});}
function renderLogScopeAnalysis(logState){const entries=logScopeEntries(logState);if(!entries.length)return renderEmptyPanel("No log entries loaded","Open a complete log file first, then run Detailed Log Analysis.");const counts=logScopeLevelCounts(entries);const loggerRows=logScopeLoggerCounts(entries);const filtered=logScopeFilteredEntries(logState);const cards=renderSummaryTiles([{label:"Entries",value:entries.length,copy:"Lines parsed from the complete log."},{label:"Problem Indicators",value:entries.filter(function(entry){return entry.problem;}).length,copy:"Errors, warnings, exceptions, failures, stuck, denied, and timeout text.",tone:"warning"},{label:"Errors",value:counts.ERROR||0,copy:"ERROR, SEVERE, CRITICAL, FATAL, ORA, BEA, and IAM codes.",tone:(counts.ERROR||0)>0?"critical":"healthy"},{label:"Warnings",value:counts.WARNING||0,copy:"WARNING and WARN entries.",tone:(counts.WARNING||0)>0?"warning":"healthy"},{label:"Loggers",value:loggerRows.length,copy:"Distinct Java logger names detected."}]);return`<div class="logscope-workspace">${renderLogScopeRefinePanel(logState,entries,counts,loggerRows)}<section class="logscope-analysis-main">${cards}<div class="logscope-search-grid is-expanded"><div class="field"><label>Search All Parsed Text</label><input class="input-field" type="search" data-logscope-filter-text placeholder="ECID, logger, message, host, user, error..." value="${escapeHtml(logState.filterText||"")}"></div><div class="field"><label>Logger Contains</label><input class="input-field" type="search" data-logscope-logger-filter placeholder="oracle.iam, weblogic, ODL..." value="${escapeHtml(logState.filterLogger||"")}"></div><label class="checkbox-row logscope-problem-toggle"><input type="checkbox" data-logscope-problems-only ${logState.analysisOnlyProblems?"checked":""}> Show problems only</label><label class="checkbox-row logscope-problem-toggle"><input type="checkbox" data-logscope-java-stacks-only ${logState.javaStacksOnly?"checked":""}> Only Java exceptions / stacks</label><button class="button" type="button" data-logscope-clear-filters>Clear Filters</button></div><div class="logscope-analysis-count">${filtered.length} matching entries across the loaded ${escapeHtml(logState.logReadMode==="tail"?"tail":"complete log")}.</div>${!filtered.length?renderEmptyPanel("No matching log entries","Adjust the search text, loggers, levels, or Java stack filter to broaden the detailed analysis."):`<div class="logscope-analysis-list">${filtered.slice(0,2000).map(function(entry){return`<article class="logscope-entry ${entry.problem?"is-problem":""} ${logScopeJavaStackHit(entry)?"is-java-stack":""}"><div class="logscope-entry-head"><span class="logscope-level logscope-level-${entry.level.toLowerCase()}">${escapeHtml(entry.level)}</span>${entry.timestamp?`<strong>${escapeHtml(entry.timestamp)}</strong>`:""}${entry.code?`<span>${escapeHtml(entry.code)}</span>`:""}${entry.logger?`<span class="logscope-entry-logger">${escapeHtml(entry.logger)}</span>`:""}${logScopeJavaStackHit(entry)?'<span class="logscope-stack-chip">Java stack</span>':""}<span>line ${entry.index}</span></div><pre>${escapeHtml(entry.line)}</pre></article>`;}).join("")}</div>${filtered.length>2000?`<p class="table-note">Showing the first 2000 matching entries. Narrow the filters to inspect a smaller set.</p>`:""}`}</section></div>`;}
