renderSidebar=function(){const activeEnvironment=selectedEnvironmentRecord()||selectedEnvironmentOverview()||{};const applicationMeta=applicationSectionMeta(activeEnvironment);const heading=isAdministrationContext()?"Administration":environmentName(activeEnvironment);if(isAdministrationContext()){const items=[{id:"admin-environments",label:"Environments",copy:"Add and maintain Oracle IAM environments."},{id:"admin-notifications",label:"Email Notifications",copy:"Manage SMTP delivery and recipients."},{id:"admin-help",label:"Support Center",copy:"Version, upgrades, service health, and support tools."}];refs.sidebarNav.innerHTML=`<p class="nav-heading">${escapeHtml(heading)}</p>${items.map(function(item){return`<button class="nav-item ${state.activeSection===item.id?"is-active":""}" type="button" data-section="${escapeHtml(item.id)}"><span class="nav-item-label">${escapeHtml(item.label)}</span><span class="nav-item-copy">${escapeHtml(item.copy)}</span></button>`;}).join("")}`;return;}state.navGroups=normalizeEnvironmentNavGroups(state.navGroups);const groups=[{id:"overview",label:"Overview",expanded:state.navGroups.overview,items:[{id:"env-overview-details",label:"Environment Details",copy:"Profile, collection, bootstrap, and operations."}]},{id:"infrastructure",label:"Infrastructure Metrics",expanded:state.navGroups.infrastructure,items:[{id:"env-server",label:"Server Metrics",copy:"CPU, load average, memory, disk, and processes."}]},{id:"applications",label:"Application Metrics",expanded:state.navGroups.applications,items:[{id:"env-applications",label:applicationMeta.label==="Application Metrics"?"Product Views":applicationMeta.label,copy:applicationMeta.copy}]},{id:"logs",label:"Log Analysis",expanded:state.navGroups.logs,items:[{id:"env-logscope",label:"Log Analyzer",copy:"Browse, load, tail, and analyze product logs."}]}];refs.sidebarNav.innerHTML=`<p class="nav-heading">${escapeHtml(heading)}</p>${groups.map(renderSidebarGroup).join("")}`;};
const renderOperationsBlocksBeforeV76=renderOperationsBlocks;
