renderCombinedOverviewPage=function(){const record=selectedEnvironmentRecord()||{};const dashboard=state.dashboard||{};const base=renderOverviewPage();const operations=renderOperationsBlocks(record,dashboard,false);const marker='<div class="content-grid two-column"><section class="panel"><div class="panel-header"><div><h3 class="panel-title">Environment Profile</h3>';if(base.includes(marker))return base.replace(marker,operations+marker);return base.replace(/<\/div>\s*$/,operations+"</div>");};
function processServerNameFromCommand(command){return processTokenValue(command,/(?:-Dweblogic\.Name=|weblogic\.Name=)([^\s]+)/)||processTokenValue(command,/(?:^|\s)(?:\.\/)?startManagedWebLogic(?:\.sh|\.s)?\s+([^\s]+)/i)||processTokenValue(command,/managedServerName=([^\s]+)/i);}
function processIsManagedServer(row){const serverName=String((row||{}).serverName||"").trim();return row&&row.product==="WebLogic"&&(row.role==="Managed Server"||(serverName&&serverName!=="AdminServer")||/startManagedWebLogic/i.test(String(row.command||row.raw||"")));}
parseMatchedProcess=function(item){const objectItem=item&&typeof item==="object";const raw=objectItem?String(item.raw||item.command||item.cmd||"").trim():String(item||"").trim();const match=raw.match(/^(\S+)\s+(\d+)\s+([\s\S]*)$/);const user=objectItem?item.user||item.owner||(match?match[1]:"-"):(match?match[1]:"-");const pid=objectItem?item.pid||(match?match[2]:"-"):(match?match[2]:"-");const command=objectItem?String(item.command||item.cmd||item.raw||raw).trim():(match?match[3]:raw);const serverName=String(item&&item.serverName?item.serverName:processServerNameFromCommand(command)||"").trim();const domainHome=processTokenValue(command,/-D(?:domain\.home|weblogic\.RootDirectory)=([^\s]+)/)||String(item&&item.domainHome||"");const javaHome=processTokenValue(command,/-Dweblogic\.nodemanager\.JavaHome=([^\s]+)/)||processTokenValue(command,/^\s*(\/[^\s]*\/bin\/java)\b/)||String(item&&item.javaHome||"");const xms=processTokenValue(command,/-Xms([^\s]+)/)||String(item&&item.xms||"");const xmx=processTokenValue(command,/-Xmx([^\s]+)/)||String(item&&item.xmx||"");let role=item&&item.role?item.role:"Process";let product=item&&item.product?item.product:"Server";let tone=item&&item.tone?item.tone:"neutral";if(/grep\s+-E|grep\s+/i.test(command)){role="Matcher Command";product="Collector";tone="muted";}else if(serverName){role=serverName==="AdminServer"?"Admin Server":"Managed Server";product="WebLogic";tone=serverName==="AdminServer"?"admin":"managed";}else if(/startManagedWebLogic/i.test(command)){role="Managed Server";product="WebLogic";tone="managed";}else if(/weblogic\.NodeManager/i.test(command)){role="Node Manager";product="WebLogic";tone="info";}else if(/startWebLogic/i.test(command)){role="Start Script";product="WebLogic";tone="info";}else if(/oidldapd/i.test(command)){role="OID LDAP Process";product="OID";tone="directory";}else if(/java/i.test(command)){role="Java Process";product="Java";tone="info";}const firstToken=String(command||"").split(/\s+/)[0]||"-";return Object.assign({},objectItem?item:{},{raw:raw,command:command,user:user,pid:pid,role:role,product:product,tone:tone,serverName:serverName,domainHome:domainHome,javaHome:javaHome,xms:xms,xmx:xmx,executable:processBasename(firstToken)});};
renderCodeList=function(lines,emptyCopy){const rows=coerceList(lines).map(parseMatchedProcess).filter(function(row){return row.raw||row.command;});if(!rows.length)return`<p class="table-note">${escapeHtml(emptyCopy||"No matching processes were discovered.")}</p>`;const weblogicCount=rows.filter(function(row){return row.product==="WebLogic";}).length;const managedCount=rows.filter(processIsManagedServer).length;const utilityCount=rows.filter(function(row){return row.tone==="muted"||row.role==="Start Script"||row.role==="Matcher Command";}).length;return`<div class="process-dashboard"><div class="process-summary-strip"><div><span>Total processes</span><strong>${escapeHtml(rows.length)}</strong></div><div><span>WebLogic</span><strong>${escapeHtml(weblogicCount)}</strong></div><div><span>Managed servers</span><strong>${escapeHtml(managedCount)}</strong></div><div><span>Scripts / matchers</span><strong>${escapeHtml(utilityCount)}</strong></div></div><div class="process-card-grid">${renderProcessCards(rows)}</div></div>`;};
function renderTopbarUserMenu(){const menu=document.getElementById("topbar-user-menu");const button=document.querySelector("[data-user-menu-toggle]");if(!menu||!button)return;const open=Boolean(state.userMenuOpen);menu.classList.toggle("hidden",!open);button.setAttribute("aria-expanded",open?"true":"false");}
function assistanceModalRoot(){let node=document.getElementById("assistance-modal-root");if(!node){node=document.createElement("div");node.id="assistance-modal-root";document.body.appendChild(node);}return node;}
function renderUserGuideBody(){return`<div class="guide-layout"><section class="guide-section"><h4>1. Create A Connection Profile</h4><p>Open Administration, create an environment, select products such as WebLogic, OIG/OIM, OUD, OID, or OAA, and save the product homes, domain homes, credentials, and SSH access needed by that product.</p></section><section class="guide-section"><h4>2. Bootstrap And Collect</h4><p>Use Create And Bootstrap for new profiles. After bootstrap, the dashboard switches to the installed runtime SSH key. Use Run Jobs Now when you want a fresh snapshot before the scheduled collector interval.</p></section><section class="guide-section"><h4>3. Read Server Metrics</h4><p>Server Metrics shows host health, CPU, memory, disk, cluster nodes, and matched WebLogic or directory processes. Cluster nodes discovered from WebLogic inventory are grouped into per-node tabs.</p></section><section class="guide-section"><h4>4. Read Application Metrics</h4><p>Application Metrics shows product tabs. ORACLE_HOME tabs include OPatch inventory, current patch level, KA754 recommendations, certificates, and product-specific runtime details.</p></section><section class="guide-section"><h4>5. Analyze Logs</h4><p>Open Log Analyzer, select a server or product log source, then double-click a file to load the complete log. Use Tail for recent entries and Detailed Log Analysis for level, logger, text, and Java stack filters.</p></section><section class="guide-section"><h4>6. Upgrade The Dashboard</h4><p>Open Support Center to check the running version, configure GitHub proxy if needed, and queue a GitHub upgrade through the host helper. Refresh the browser after the service restarts.</p></section><section class="guide-section"><h4>7. Troubleshooting</h4><p>If a collection fails, check Environment Details for Run Jobs Now status and collector output. Then verify SSH, product credentials, ORACLE_HOME paths, DOMAIN_HOME paths, and the collector log path shown on the page.</p></section></div>`;}
function renderFeedbackBody(){const version=currentVersion();const env=selectedEnvironmentRecord()||selectedEnvironmentOverview()||{};return`<div class="guide-layout feedback-layout"><section class="guide-section"><h4>What To Include</h4><p>Include dashboard version ${escapeHtml(version)}, environment ${escapeHtml(env.name||state.activeContext||"Administration")}, the active page name, a screenshot, and the collector log output when reporting an issue.</p></section><section class="guide-section"><h4>Common Checks</h4><p>Use Support Center for service paths and health details. Use Log Analyzer for product log evidence. Use Run Jobs Now from Environment Details to reproduce collection problems with a fresh tail.</p></section><section class="guide-section"><h4>Feedback Focus</h4><p>Useful feedback includes missing product metrics, confusing labels, slow collector commands, patch recommendation gaps, and logs that should be parsed more intelligently.</p></section></div>`;}
function renderUninstallSupportPanel(){const help=(state.appShell||{}).help||{};const commands=coerceList(help.uninstallCommands);if(!commands.length)return"";return`<section class="panel"><div class="panel-header"><div><h3 class="panel-title">Uninstall</h3><p class="panel-copy">Remove the dashboard service from this host. The optional state-removal step deletes saved connection profiles, encrypted passwords, runtime SSH keys, snapshots, and logs.</p></div></div><div class="table-wrap"><table><thead><tr><th>Step</th><th>Command</th></tr></thead><tbody>${commands.map(function(item){return`<tr><td>${escapeHtml(item.label||"-")}</td><td><code>${escapeHtml(item.command||"-")}</code></td></tr>`;}).join("")}</tbody></table></div><p class="table-note">To keep customer connection profiles for a later reinstall, skip the optional runtime config and customer state removal step.</p></section>`;}
