const WEBLOGIC_DEFAULT_SELECTED_V77=["serverDetails","runtimeStatus","jta","jvm","threadPool","sockets"];
state.loadedWeblogicMetricGroups=WEBLOGIC_DEFAULT_SELECTED_V77.slice();
function environmentStatusReasonItemsV77(dashboard){
const rows=environmentStatusReasonItems(dashboard).slice();
const server=((dashboard||{}).server)||{};
coerceList(server.clusterNodes).forEach(function(node,index){
const nodeName=node.nodeName||`Node ${index+1}`;
if(node.reachable===false)rows.push({key:`${nodeName} Reachability`,value:node.error||`${node.configuredHost||"Cluster node"} is unreachable.`,tone:"critical"});
const health=(node.health||{});
const checks=health.checks||{};
const thresholds=health.thresholds||{};
Object.keys(checks).forEach(function(key){
const check=checks[key]||{};
const severity=String(check.severity||"").toLowerCase();
if(!["critical","warning"].includes(severity))return;
const threshold=thresholdText(((thresholds[key]||{})[severity]),key);
rows.push({key:`${nodeName} ${check.label||startCase(key)}`,value:`${healthCheckValue(check,key)} is ${severity}${threshold?`; ${threshold}`:""}`,tone:severity});
});
});
const seen=new Set();
return rows.filter(function(row){
const key=`${row.key}|${row.value}`;
if(seen.has(key))return false;
seen.add(key);
return true;
});
}
function environmentStatusReasonTextV77(dashboard,label){
const rows=environmentStatusReasonItemsV77(dashboard);
if(rows.length)return rows.map(function(row){return`${row.key}: ${row.value}`;}).join("\n");
const job=((dashboard||{}).job)||{};
if(job.tail)return String(job.tail).split(/\r?\n/).filter(Boolean).slice(-3).join("\n");
return `${label||"Environment status"} is based on the latest collector snapshot.`;
}
function renderEnvironmentStatusWithReasonV77(status,label,dashboard){
const reason=environmentStatusReasonTextV77(dashboard,label);
const lines=reason.split(/\r?\n/).filter(Boolean).slice(0,8);
return`<span class="status-reason-wrapper" tabindex="0" title="${escapeHtml(reason)}" aria-label="${escapeHtml(`${label||statusLabel(status)}. ${reason}`)}">${renderStatusPill(status,label)}<span class="status-reason-popover" role="tooltip"><strong>Status Reason</strong>${lines.map(function(line){return`<span>${escapeHtml(line)}</span>`;}).join("")}</span></span>`;
}
