async function downloadSelectedLogScopeFilesV80(){
const envId=currentEnvironmentId();
const logState=currentLogScopeState();
const files=logScopeSelectedFilesV80(logState,false);
if(!files.length){setMessage("Select one or more log files to download.","error");return;}
setMessage(`Preparing ${files.length} selected log file${files.length===1?"":"s"} for download...`,"info");
const response=await fetch(`/api/environments/${encodeURIComponent(envId)}/logs/download`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({profileId:logState.activeProfileId,groupId:logState.activeGroupId,fileNames:files})});
if(!response.ok){
let message=`Download failed with status ${response.status}.`;
try{const payload=await response.json();message=payload.error||message;}catch(error){}
throw new Error(message);
}
const blob=await response.blob();
const url=window.URL.createObjectURL(blob);
const link=document.createElement("a");
link.href=url;
link.download=logScopeDownloadNameV80(response);
document.body.appendChild(link);
link.click();
link.remove();
window.setTimeout(function(){window.URL.revokeObjectURL(url);},1500);
setMessage(`Prepared ${files.length} selected log file${files.length===1?"":"s"} for download.`,"success");
}
