return`<section class="panel certificate-panel is-v79 oam-certificate-panel"><div class="panel-header"><div><h3 class="panel-title">OAM Certificates</h3><p class="panel-copy">Readable OAM keystore and SSL certificate entries are shown first. Endpoint probes and keystore checks that need credentials are kept in a review drawer.</p></div></div>${rows.length===0?renderEmptyPanel("No OAM certificates",error||"No OAM certificate details were returned."):`${renderCertificateSummaryV79(useful.length?useful:rows)}${useful.length?renderCertificateCardsV79(useful,false):renderEmptyPanel("No readable certificate entries","OpenSSL endpoint checks did not return certificates and OAM keystore passwords could not be resolved.")}${useful.length?renderCertificateTableV79(useful,false):""}${unavailableRows}${error?`<p class="table-note">${escapeHtml(error)}</p>`:""}`}</section>`;
